    const calculateDuration = () => {
        const start = document.getElementById('start-time')?.value;
        const end = document.getElementById('end-time')?.value;
        const durationField = document.getElementById('duration');

        if (start && end && durationField) {
            const startParts = start.split(':');
            const endParts = end.split(':');
            const startMin = parseInt(startParts[0]) * 60 + parseInt(startParts[1]);
            const endMin = parseInt(endParts[0]) * 60 + parseInt(endParts[1]);
            const duration = endMin - startMin;
            durationField.value = duration > 0 ? `${duration} min` : 'Invalid';
        }
    };

    const toggleCoAgentSection = () => {
        const section = document.getElementById('co-agent-section');
        const checked = document.getElementById('allow-join')?.checked;
        if (section) section.style.display = checked ? 'block' : 'none';
        if (!checked) _selectedCoAgents = [];
        renderCoAgents();
    };

    const toggleEventForm = () => {
        const val = document.querySelector('input[name="event-selection"]:checked')?.value;
        const existing = document.getElementById('existing-event-section');
        const next = document.getElementById('new-event-section');
        if (existing) existing.style.display = val === 'existing' ? 'block' : 'none';
        if (next) next.style.display = val === 'new' ? 'block' : 'none';
    };

    const openCpsCreateEventModal = () => {
        const content = `
            ${buildEventCategoriesField([])}
            <div class="form-group"><label>Title*</label><input type="text" id="mkt-title" class="form-control"></div>
            <div class="form-group"><label>Ticket Price (RM)</label><input type="number" id="mkt-price" class="form-control" value="0"></div>
            <div class="form-group"><label>Early Bird Price (RM)</label><input type="text" id="mkt-early-bird-price" class="form-control" placeholder="e.g. 199"></div>
            <div class="form-group"><label>Group Purchase Price (RM)</label><input type="text" id="mkt-group-price" class="form-control" placeholder="e.g. 299 (min 5 pax)"></div>
            <div class="form-group"><label>Duration</label><input type="text" id="mkt-duration" class="form-control" placeholder="e.g. 2 hours"></div>
            <div class="form-group"><label>Target Group</label><input type="text" id="mkt-target" class="form-control"></div>
            <div class="form-group"><label>Location</label><input type="text" id="mkt-location" class="form-control" placeholder="e.g. KL, Online"></div>
            <div class="form-group"><label>Speaker</label><input type="text" id="mkt-speaker" class="form-control" placeholder="e.g. Master Tan"></div>
            <div class="form-group"><label>Description</label><textarea id="mkt-desc" class="form-control"></textarea></div>
            <div class="form-group"><label>Remarks</label><input type="text" id="mkt-remarks" class="form-control"></div>
            <div class="form-group"><label><input type="checkbox" id="mkt-active" checked> Is Active</label></div>
        `;
        UI.showModal('Add New Event', content, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: 'Save', type: 'primary', action: '(async () => { await app.saveCpsNewEvent(); })()' }
        ]);
    };

    const saveCpsNewEvent = async () => {
        const title = document.getElementById('mkt-title')?.value?.trim();
        if (!title) return UI.toast.error('Title is required');

        const catCheckboxes = document.querySelectorAll('#mkt-event-categories .mkt-event-category-cb:checked');
        const selectedCats = Array.from(catCheckboxes).map(cb => cb.value);
        const othersCb = document.getElementById('mkt-event-cat-others-cb');
        const othersInput = document.getElementById('mkt-event-cat-others-input');
        if (othersCb && othersCb.checked && othersInput && othersInput.value.trim()) {
            othersInput.value.split(',').map(s => s.trim()).filter(Boolean).forEach(c => {
                if (!selectedCats.includes(c)) selectedCats.push(c);
            });
        }
        if (!selectedCats.length) return UI.toast.error('At least one category is required');

        const data = {
            // `title` is the real DB column; older code reads `event_title`
            // first and falls back, so writing `title` is sufficient.
            title: title,
            ticket_price: parseFloat(document.getElementById('mkt-price')?.value) || 0,
            early_bird_price: document.getElementById('mkt-early-bird-price')?.value || '',
            group_purchase_price: document.getElementById('mkt-group-price')?.value || '',
            duration: document.getElementById('mkt-duration')?.value || '',
            target_group: document.getElementById('mkt-target')?.value || '',
            location: document.getElementById('mkt-location')?.value || '',
            speaker: document.getElementById('mkt-speaker')?.value || '',
            description: document.getElementById('mkt-desc')?.value || '',
            remarks: document.getElementById('mkt-remarks')?.value || '',
            is_active: document.getElementById('mkt-active')?.checked ?? true,
            status: document.getElementById('mkt-active')?.checked ? 'active' : 'inactive',
            categories: JSON.stringify(selectedCats),
            created_by: _currentUser ? _currentUser.id : null,
            updated_at: new Date().toISOString()
        };

        try {
            const newEvent = await AppDataStore.create('events', data);
            UI.hideModal();
            UI.toast.success('Event created successfully');

            // Refresh existing events dropdown and auto-select the new event
            const dropdown = document.getElementById('existing-event');
            if (dropdown) {
                const allEvents = await AppDataStore.getAll('events');
                const activeEvents = allEvents.filter(e => e.is_active !== false && e.status !== 'inactive');
                dropdown.innerHTML = '<option value="">-- Select --</option>' +
                    activeEvents.map(e => `<option value="${e.id}" ${e.id === newEvent.id ? 'selected' : ''}>${e.event_title || e.title || 'Untitled Event'}</option>`).join('');
                showSelectedEventDetails(newEvent.id);
            }

            // Switch to "Select Existing" with the new event selected
            const existingRadio = document.querySelector('input[name="event-selection"][value="existing"]');
            if (existingRadio) {
                existingRadio.checked = true;
                toggleEventForm();
            }
        } catch (err) {
            console.error('saveCpsNewEvent error:', err);
            UI.toast.error('Save failed: ' + (err.message || err));
        }
    };

    const showSelectedEventDetails = async (eventId) => {
        const preview = document.getElementById('event-details-preview');
        if (!preview) return;
        if (!eventId) { preview.innerHTML = ''; return; }
        const ev = await AppDataStore.getById('events', eventId);
        if (!ev) { preview.innerHTML = ''; return; }
        preview.innerHTML = `
            <div style="margin-top:12px; padding:12px; background:var(--gray-50,#faf9f7); border:1px solid var(--border,#e5e0d8); border-radius:8px; font-size:13px;">
                <div style="font-weight:600; margin-bottom:8px; color:var(--primary);">Event Details</div>
                <div style="display:grid; grid-template-columns:110px 1fr; gap:4px 8px;">
                    <span style="color:var(--gray-400);">Type:</span><span>${ev.event_type || '-'}</span>
                    <span style="color:var(--gray-400);">Title:</span><span><strong>${ev.event_title || ev.title || '-'}</strong></span>
                    <span style="color:var(--gray-400);">Speaker:</span><span>${ev.speaker || '-'}</span>
                    <span style="color:var(--gray-400);">Duration:</span><span>${ev.duration || '-'}</span>
                    <span style="color:var(--gray-400);">Venue:</span><span>${ev.location || ev.venue || '-'}</span>
                    <span style="color:var(--gray-400);">Ticket Price:</span><span>${ev.ticket_price ? 'RM ' + ev.ticket_price : '-'}</span>
                    <span style="color:var(--gray-400);">Early Bird:</span><span>${ev.early_bird_price || '-'}</span>
                    <span style="color:var(--gray-400);">Group Price:</span><span>${ev.group_purchase_price || '-'}</span>
                    <span style="color:var(--gray-400);">Target Group:</span><span>${ev.target_group || '-'}</span>
                    <span style="color:var(--gray-400);">Description:</span><span>${ev.description || '-'}</span>
                </div>
            </div>
        `;
    };

    const toggleAttendeePaid = async (attendeeId, checked) => {
        await AppDataStore.update('event_attendees', attendeeId, { paid: checked });
    };

    const toggleAttendeeTicket = async (attendeeId, checked) => {
        await AppDataStore.update('event_attendees', attendeeId, { ticket_created: checked });
    };

    const toggleAttendeeAttended = async (attendeeId, checked, entityId, entityType, eventId, activityDate) => {
        const status = checked ? 'Attended' : 'Registered';
        await AppDataStore.update('event_attendees', attendeeId, { attended: checked, attendance_status: status });

        // Write back to event_registrations so it appears in prospect/customer profile
        if (entityId && eventId) {
            try {
                const existing = (await AppDataStore.getAll('event_registrations')).find(
                    r => r.event_id == eventId && r.attendee_id == entityId
                );
                if (existing) {
                    await AppDataStore.update('event_registrations', existing.id, { attendance_status: status });
                } else {
                    await AppDataStore.create('event_registrations', {
                        event_id: eventId,
                        attendee_id: entityId,
                        attendee_type: entityType || 'prospect',
                        attendance_status: status,
                        event_date: activityDate || new Date().toISOString().split('T')[0],
                        points_awarded: 0,
                        created_at: new Date().toISOString()
                    });
                }
                UI.toast.success(checked ? 'Marked as Attended' : 'Attendance removed');

                // Trigger follow-up: event attendance triggers (data-driven)
                if (checked && entityId && eventId) {
                    dispatchOnEventAttendanceTriggers(entityId, entityType || 'prospect', eventId, activityDate).catch(e => console.warn('Event attendance follow-up failed:', e));
                }
            } catch (err) {
                console.error('toggleAttendeeAttended write-back error:', err);
            }
        }
    };

    const toggleAttendeeUnattended = async (attendeeId, checked, entityId, entityType, eventId, activityDate) => {
        // Mutually exclusive with Attended — checking Unattended marks as No Show, unchecking
        // returns to plain Registered.
        const status = checked ? 'No Show' : 'Registered';
        await AppDataStore.update('event_attendees', attendeeId, { attended: false, attendance_status: status });

        if (entityId && eventId) {
            try {
                const existing = (await AppDataStore.getAll('event_registrations')).find(
                    r => r.event_id == eventId && r.attendee_id == entityId
                );
                if (existing) {
                    await AppDataStore.update('event_registrations', existing.id, { attendance_status: status });
                } else {
                    await AppDataStore.create('event_registrations', {
                        event_id: eventId,
                        attendee_id: entityId,
                        attendee_type: entityType || 'prospect',
                        attendance_status: status,
                        event_date: activityDate || new Date().toISOString().split('T')[0],
                        points_awarded: 0,
                        created_at: new Date().toISOString()
                    });
                }
                UI.toast.success(checked ? 'Marked as Unattended (No Show)' : 'Unattended cleared');
            } catch (err) {
                console.error('toggleAttendeeUnattended write-back error:', err);
            }
        }
        // Refresh the modal so the Attended checkbox unticks if it was on
        const allActivities = await AppDataStore.getAll('activities');
        const acts = allActivities.filter(a => a.event_id == eventId && a.activity_date == activityDate);
        if (acts.length > 0) await app.viewActivityDetails(acts[0].id);
    };

    const toggleLifeChartType = async (prospectId, dateType, checked) => {
        // Read the FRESHEST state (bypass cache) so concurrent toggles on both
        // solar and lunar don't race and overwrite each other.
        AppDataStore.invalidateCache('prospects');
        const prospect = await AppDataStore.getById('prospects', prospectId);
        if (!prospect) {
            UI.toast.error('Prospect not found');
            return;
        }
        const current = prospect.life_chart_type || '';
        let newType;
        if (dateType === 'solar') {
            const lunarOn = current === 'lunar' || current === 'both';
            newType = checked ? (lunarOn ? 'both' : 'solar') : (lunarOn ? 'lunar' : null);
        } else {
            const solarOn = current === 'solar' || current === 'both';
            newType = checked ? (solarOn ? 'both' : 'lunar') : (solarOn ? 'solar' : null);
        }

        // Write DIRECTLY via service-role REST instead of AppDataStore.update().
        // AppDataStore.update() silently falls back to localStorage on any error
        // (schema cache miss, RLS rejection, network blip) and returns without
        // throwing — so the toast would show "updated" while the server value
        // was never touched, and the next profile re-render would show the
        // checkbox reverting to its previous state ("tick doesn't flow over").
        // A direct PATCH with the service-role key bypasses RLS entirely and
        // surfaces real errors to the user.
        let writeOk = false;
        if (window.SUPABASE_URL && window.SUPABASE_SR) {
            try {
                const resp = await fetch(
                    `${window.SUPABASE_URL}/rest/v1/prospects?id=eq.${encodeURIComponent(prospectId)}`,
                    {
                        method: 'PATCH',
                        headers: {
                            'Content-Type': 'application/json',
                            'Authorization': `Bearer ${window.SUPABASE_SR}`,
                            'apikey': window.SUPABASE_SR,
                            'Prefer': 'return=representation'
                        },
                        body: JSON.stringify({ life_chart_type: newType })
                    }
                );
                if (resp.ok) {
                    writeOk = true;
                } else {
                    const errTxt = await resp.text();
                    console.warn('toggleLifeChartType PATCH failed:', resp.status, errTxt);
                }
            } catch (e) {
                console.warn('toggleLifeChartType PATCH threw:', e);
            }
        }

        // Fallback path: use AppDataStore.update() if the direct PATCH was unavailable.
        if (!writeOk) {
            try {
                await AppDataStore.update('prospects', prospectId, { life_chart_type: newType });
                writeOk = true;
            } catch (e) {
                console.warn('AppDataStore.update fallback failed:', e);
            }
        }

        if (!writeOk) {
            UI.toast.error('Failed to save life chart type — please try again');
            // Re-render to revert the checkbox to its actual persisted state
            const bodyEl = document.getElementById(`acc-body-personal-${prospectId}`);
            if (bodyEl) await switchProspectTab('personal', prospectId, null, bodyEl);
            return;
        }

        // Update both checkboxes directly in the DOM instead of re-rendering
        // the whole tab.  A full re-render via switchProspectTab fetches the
        // prospect again — if the read returns stale/cached data the checkbox
        // silently reverts to its old state ("tick doesn't stick").
        AppDataStore.invalidateCache('prospects');
        UI.toast.success('Life chart type updated');
        const bodyEl = document.getElementById(`acc-body-personal-${prospectId}`);
        if (bodyEl) {
            bodyEl.querySelectorAll('input[type="checkbox"]').forEach(chk => {
                const oc = chk.getAttribute('onchange') || '';
                if (oc.includes("'solar'")) chk.checked = newType === 'solar' || newType === 'both';
                else if (oc.includes("'lunar'")) chk.checked = newType === 'lunar' || newType === 'both';
            });
        }
    };

    const showAttendeeDetails = async (entityId, type) => {
        if (!entityId) { UI.toast.error('No profile available'); return; }
        const table = type === 'customer' ? 'customers' : 'prospects';
        const person = await AppDataStore.getById(table, entityId);
        if (!person) { UI.toast.error('Profile not found'); return; }
        const agent = person.responsible_agent_id ? await AppDataStore.getById('users', person.responsible_agent_id) : null;
        const row = (label, value) => `
            <div style="display:flex;gap:8px;padding:8px 0;border-bottom:1px solid var(--border,#e5e0d8);">
                <span style="width:140px;font-size:12px;color:var(--gray-400);flex-shrink:0;">${label}</span>
                <span style="font-size:13px;font-weight:500;">${value || '—'}</span>
            </div>`;
        const content = `
            <div style="padding:4px 0;">
                ${row('Name', person.full_name)}
                ${row('IC Number', person.ic_number)}
                ${row('Email', person.email)}
                ${row('Date of Birth', person.date_of_birth)}
                ${row('Lunar Date of Birth', person.lunar_birth)}
                ${row('Occupation', person.occupation)}
                ${row('Agent', agent?.full_name)}
            </div>`;
        UI.showModal(person.full_name || 'Attendee Details', content, [
            { label: 'Close', type: 'secondary', action: 'UI.hideModal()' }
        ]);
    };

    const goToProspectEventNotes = async (entityId, eventId, entityType, activityDate) => {
        if (!entityId) return;
        // Ensure event_registrations record exists so it shows in prospect's Activities & Events tab
        try {
            const existing = (await AppDataStore.getAll('event_registrations')).find(
                r => r.event_id == eventId && r.attendee_id == entityId
            );
            if (!existing) {
                await AppDataStore.create('event_registrations', {
                    event_id: eventId,
                    attendee_id: entityId,
                    attendee_type: entityType || 'prospect',
                    attendance_status: 'Registered',
                    event_date: activityDate || new Date().toISOString().split('T')[0],
                    points_awarded: 0,
                    created_at: new Date().toISOString()
                });
            }
        } catch (err) {
            console.warn('goToProspectEventNotes: could not write event_registrations', err);
        }
        UI.hideModal();
        app.showProspectDetail(entityId);
    };

    const showAddAttendeeSearch = async (eventId, activityId) => {
        const [prospects, customers] = await Promise.all([AppDataStore.getAll('prospects'), AppDataStore.getAll('customers')]);
        // BUG FIX 2026-04-11: dedupe by normalized phone (fallback: name) within each list
        // so the same person (accidental duplicate row) doesn't show twice in the picker.
        const dedupe = (list, type) => {
            const seen = new Map();
            for (const p of list) {
                const key = (p.phone && String(p.phone).replace(/\D+/g,''))
                    || `name:${String(p.full_name||'').trim().toLowerCase()}`;
                if (!key || key === 'name:') continue;
                if (!seen.has(key)) seen.set(key, { ...p, _type: type });
            }
            return Array.from(seen.values());
        };
        window._addAttAll = [...dedupe(prospects, 'prospect'), ...dedupe(customers, 'customer')];
        window._addAttSelected = null;
        window._addAttEventId = eventId;
        window._addAttActivityId = activityId;
        const content = `
            <div class="form-group">
                <label>Search Prospect / Customer</label>
                <input type="text" id="add-att-search" class="form-control" placeholder="Type name or phone..." oninput="app.searchAddAttendee(this.value)">
                <div id="add-att-results" style="border:1px solid var(--border,#e5e0d8);border-radius:4px;max-height:160px;overflow-y:auto;display:none;background:#fff;"></div>
            </div>
            <div id="add-att-name" style="margin-top:8px;font-weight:600;color:var(--primary);min-height:20px;"></div>
            <div style="margin-top:12px;padding-top:12px;border-top:1px solid var(--border,#e5e0d8);">
                <div style="font-size:12px;color:var(--gray-400);margin-bottom:6px;">New person not in system?</div>
                <button class="btn secondary btn-sm" onclick="app.showFTFAttendeeForm()" style="width:100%;">➕ First Time Friend (New Prospect)</button>
            </div>
        `;
        UI.showModal('Add Attendee', content, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: 'Add', type: 'primary', action: '(async()=>{ await app.confirmAddAttendee(); })()' }
        ]);
    };

    // v6: Search & add an agent/consultant attendee.
    // Uses the users table filtered by consultant role (Level 7) or any agent level.
    // Writes to event_attendees with attendee_type='agent'.
    const showAddConsultantSearch = async (eventId, activityId) => {
        const users = await AppDataStore.getAll('users');
        // Filter to consultants + agents (Level 3-12). Exclude customers/referrers/inactive.
        const filtered = users.filter(u => {
            if (u.status === 'inactive') return false;
            const lvl = _getUserLevel(u);
            return lvl >= 3 && lvl <= 12; // agents/consultants only; admins (1-2), customers (13), referrers (14) excluded
        });
        // Dedupe by email (fallback: normalized name) — keep the most senior (lowest level) row,
        // then the oldest created_at. Defensive net against stray duplicate rows in the users table.
        const seen = new Map();
        for (const u of filtered) {
            const key = (u.email && String(u.email).trim().toLowerCase())
                || `name:${String(u.full_name || '').trim().toLowerCase()}`;
            if (!key || key === 'name:') continue;
            const prev = seen.get(key);
            if (!prev) { seen.set(key, u); continue; }
            const prevLvl = _getUserLevel(prev);
            const curLvl  = _getUserLevel(u);
            if (curLvl < prevLvl) { seen.set(key, u); continue; }
            if (curLvl === prevLvl) {
                const prevTs = Date.parse(prev.created_at || 0) || 0;
                const curTs  = Date.parse(u.created_at || 0) || 0;
                if (curTs && prevTs && curTs < prevTs) seen.set(key, u);
            }
        }
        const eligible = Array.from(seen.values());
        window._addConsultAll = eligible.map(u => ({ ...u, _type: 'agent' }));
        window._addConsultSelected = null;
        window._addConsultEventId = eventId;
        window._addConsultActivityId = activityId;
        const content = `
            <div class="form-group">
                <label>Search Agent / Consultant</label>
                <input type="text" id="add-consult-search" class="form-control" placeholder="Type name, phone, or role..." oninput="app.searchAddConsultant(this.value)">
                <div id="add-consult-results" style="border:1px solid var(--border,#e5e0d8);border-radius:4px;max-height:220px;overflow-y:auto;display:none;background:#fff;"></div>
            </div>
            <div id="add-consult-name" style="margin-top:8px;font-weight:600;color:var(--primary);min-height:20px;"></div>
            <div style="margin-top:10px;font-size:11px;color:var(--gray-400);">Showing ${eligible.length} active agents/consultants</div>
        `;
        UI.showModal('Add Agent / Consultant', content, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: 'Add', type: 'primary', action: '(async()=>{ await app.confirmAddConsultant(); })()' }
        ]);
    };

    const searchAddConsultant = (query) => {
        const q = (query || '').toLowerCase().trim();
        const res = document.getElementById('add-consult-results');
        if (!res) return;
        if (q.length < 1) { res.style.display = 'none'; res.innerHTML = ''; return; }
        const matches = (window._addConsultAll || []).filter(u =>
            (u.full_name || '').toLowerCase().includes(q)
            || (u.phone || '').includes(q)
            || (u.role || '').toLowerCase().includes(q)
            || (u.email || '').toLowerCase().includes(q)
        ).slice(0, 15);
        res.innerHTML = matches.map(u =>
            `<div style="padding:8px 12px;cursor:pointer;border-bottom:1px solid #eee;" onmousedown="app.selectAddConsultant(${u.id},'${(u.full_name||'').replace(/'/g,"\\'")}')">
                <strong>${escapeHtml(u.full_name || '')}</strong>
                <small style="color:gray;margin-left:6px;">${escapeHtml(u.role || '')}</small>
            </div>`
        ).join('') || '<div style="padding:12px;color:#9CA3AF;font-size:12px;">No matches</div>';
        res.style.display = 'block';
    };

    const selectAddConsultant = (id, name) => {
        window._addConsultSelected = { id, name };
        const nameEl = document.getElementById('add-consult-name');
        if (nameEl) nameEl.textContent = '✅ Selected: ' + name;
        const res = document.getElementById('add-consult-results');
        if (res) res.style.display = 'none';
        const input = document.getElementById('add-consult-search');
        if (input) input.value = name;
    };

    const confirmAddConsultant = async () => {
        const eventId = window._addConsultEventId;
        const activityId = window._addConsultActivityId;
        const s = window._addConsultSelected;
        if (!s) { UI.toast.error('Please select an agent first'); return; }

        // Guard against duplicate (same agent already added to this event/date)
        try {
            const existing = await AppDataStore.query('event_attendees', { activity_id: activityId });
            const dup = (existing || []).find(a =>
                a.attendee_type === 'agent'
                && String(a.entity_id || a.attendee_id) === String(s.id)
            );
            if (dup) {
                UI.toast.error(s.name + ' is already an agent attendee');
                return;
            }
        } catch (_) {}

        await AppDataStore.create('event_attendees', {
            event_id: eventId,
            activity_id: activityId,
            attendee_id: s.id,
            entity_id: s.id,
            entity_name: s.name || '',
            attendee_type: 'agent',
            attendance_status: 'Registered',
            added_by_agent_id: _currentUser?.id || null,
            added_by_name: _currentUser?.full_name || '',
            created_at: new Date().toISOString()
        });
        UI.hideModal();
        await app.viewActivityDetails(activityId);
        UI.toast.success(s.name + ' added as agent attendee');
    };

    const removeAgentAttendee = async (attendeeId, activityId) => {
        if (!confirm('Remove this agent from the event?')) return;
        try {
            await AppDataStore.delete('event_attendees', attendeeId);
            UI.toast.success('Agent removed');
            if (activityId) await app.viewActivityDetails(activityId);
        } catch (e) {
            UI.toast.error('Could not remove: ' + e.message);
        }
    };

    const searchAddAttendee = (query) => {
        const q = (query || '').toLowerCase();
        const res = document.getElementById('add-att-results');
        if (!res) return;
        if (q.length < 2) { res.style.display = 'none'; res.innerHTML = ''; return; }
        const matches = (window._addAttAll || []).filter(p =>
            (p.full_name || '').toLowerCase().includes(q) || (p.phone || '').includes(q)
        ).slice(0, 10);
        res.innerHTML = matches.map(p =>
            `<div style="padding:8px 12px;cursor:pointer;border-bottom:1px solid #eee;" onmousedown="app.selectAddAttendee(${p.id},'${(p.full_name||'').replace(/'/g,"\\'")}','${p._type}')">
                ${p.full_name} <small style="color:gray;">${p._type}</small>
            </div>`
        ).join('');
        res.style.display = matches.length ? 'block' : 'none';
    };

    const selectAddAttendee = (id, name, type) => {
        window._addAttSelected = { id, name, type };
        const nameEl = document.getElementById('add-att-name');
        if (nameEl) nameEl.textContent = '✅ Selected: ' + name;
        const res = document.getElementById('add-att-results');
        if (res) res.style.display = 'none';
        const input = document.getElementById('add-att-search');
        if (input) input.value = name;
    };

    const showFTFAttendeeForm = () => {
        // Save event context, then open full Add New Prospect modal
        const eventId = window._addAttEventId;
        const activityId = window._addAttActivityId;

        // One-time listener: after prospect is created, add as attendee
        const handler = async (e) => {
            document.removeEventListener('prospectCreated', handler);
            const prospect = e.detail;
            if (!prospect?.id || !eventId) return;
            await AppDataStore.create('event_attendees', {
                event_id: eventId,
                activity_id: activityId,
                // attendee_id is the canonical Supabase column — must be set so the record
                // remains linked to the prospect when other columns get stripped on insert.
                attendee_id: prospect.id,
                entity_id: prospect.id,
                entity_name: prospect.full_name || '',
                attendee_type: 'prospect',
                attendance_status: 'Registered',
                added_by_agent_id: _currentUser?.id || null,
                added_by_name: _currentUser?.full_name || '',
                created_at: new Date().toISOString()
            });
            await app.viewActivityDetails(activityId);
            UI.toast.success((prospect.full_name || 'New prospect') + ' added as attendee');
        };
        document.addEventListener('prospectCreated', handler);

        openProspectModal(); // opens the full Add New Prospect form
    };

    const confirmAddAttendee = async () => {
        const eventId = window._addAttEventId;
        const activityId = window._addAttActivityId;

        const s = window._addAttSelected;
        if (!s) { UI.toast.error('Please select a person first'); return; }
        await AppDataStore.create('event_attendees', {
            event_id: eventId,
            activity_id: activityId,
            // attendee_id is the actual Supabase schema column — entity_id gets stripped
            // by data.js because it doesn't exist in the table, which is why prior writes
            // persisted with no link to the prospect.
            attendee_id: s.id,
            entity_id: s.id,
            entity_name: s.name || s.full_name || '',
            attendee_type: s.type,
            attendance_status: 'Registered',
            added_by_agent_id: _currentUser?.id || null,
            added_by_name: _currentUser?.full_name || '',
            created_at: new Date().toISOString()
        });
        UI.hideModal();
        await app.viewActivityDetails(activityId);
        UI.toast.success(s.name + ' added as attendee');
    };

    const searchAttendees = () => {
        const input = document.getElementById('attendee-search');
        const resultsContainer = document.getElementById('attendee-search-results');

        if (input && resultsContainer) {
            clearTimeout(window.attendeeSearchTimeout);
            window.attendeeSearchTimeout = (async () => {
                const searchTerm = input.value.toLowerCase();
                if (searchTerm.length < 2) {
                    resultsContainer.style.display = 'none';
                    return;
                }

                const type = document.getElementById('modal-activity-type')?.value;
                const isAgentRelevant = type === 'AGENT_MEETING' || type === 'AGENT_TRAINING' || type === 'EVENT';

                let matches = [];
                if (type === 'CPS' || type === 'EVENT') {
                    const [_prospects, _customers] = await Promise.all([AppDataStore.getAll('prospects'), AppDataStore.getAll('customers')]);
                    const all = [..._prospects, ..._customers];
                    const available = all.filter(p => !_selectedAttendees.find(a => a.id === p.id && a.type !== 'agent'));
                    matches = available.filter(p =>
                        (p.full_name && p.full_name.toLowerCase().includes(searchTerm)) ||
                        (p.phone && p.phone.includes(searchTerm)) ||
                        (p.email && p.email?.toLowerCase().includes(searchTerm))
                    ).map(p => ({ ...p, type: p.is_customer ? 'customer' : 'prospect' }));
                }

                if (isAgentRelevant) {
                    const agents = (await AppDataStore.getAll('users')).filter(u =>
                        isAgent(u) &&
                        !_selectedAttendees.find(a => a.id === u.id && a.type === 'agent')
                    );
                    const agentMatches = agents.filter(a =>
                        a.full_name && a.full_name.toLowerCase().includes(searchTerm)
                    ).map(a => ({ ...a, type: 'agent' }));
                    matches = [...matches, ...agentMatches];
                }

                matches = matches.slice(0, 10);

                if (matches.length > 0) {
                    resultsContainer.innerHTML = matches.map(m => `
                        <div class="search-result-item" onclick="app.addAttendee(${m.id}, '${m.type}', '${m.full_name.replace(/'/g, "\\'")}')">
                            <div class="name">${m.full_name} <small>(${m.type})</small></div>
                            <div class="details">${m.phone || ''}</div>
                        </div>
                    `).join('');
                    resultsContainer.style.display = 'block';
                } else {
                    resultsContainer.innerHTML = '<div class="search-result-item">No matches found</div>';
                    resultsContainer.style.display = 'block';
                }
            }, 200);
        }
    };

    const addAttendee = (id, type, name) => {
        _selectedAttendees.push({
            id: id,
            name: name,
            type: type,
            status: 'Registered'
        });
        renderAttendees();
        const results = document.getElementById('attendee-search-results');
        if (results) results.style.display = 'none';
        const input = document.getElementById('attendee-search');
        if (input) input.value = '';
    };

    const removeAttendee = (id) => {
        _selectedAttendees = _selectedAttendees.filter(a => a.id !== id);
        renderAttendees();
    };

    const updateAttendeeStatus = (id, status) => {
        const attendee = _selectedAttendees.find(a => a.id === id);
        if (attendee) attendee.status = status;
    };

    const renderAttendees = () => {
        const container = document.getElementById('selected-attendees');
        if (container) {
            container.innerHTML = _selectedAttendees.map(a => `
                <div class="co-agent-tag" style="display:inline-flex; align-items:center; gap:8px; padding:6px 12px; margin-bottom:8px; background:var(--gray-100); border-radius:4px; border:1px solid var(--gray-200);">
                    <span>${a.name}</span>
                    <select class="form-control" style="width: auto; padding: 2px 6px; font-size: 11px; height: 24px;" onchange="app.updateAttendeeStatus(${a.id}, this.value)">
                        <option value="Registered" ${a.status === 'Registered' ? 'selected' : ''}>Registered</option>
                        <option value="Attended" ${a.status === 'Attended' ? 'selected' : ''}>Attended</option>
                        <option value="No Show" ${a.status === 'No Show' ? 'selected' : ''}>No Show</option>
                    </select>
                    <span class="remove" onclick="app.removeAttendee(${a.id})" style="cursor:pointer; font-weight:bold; margin-left:4px; color:var(--danger-color);">&times;</span>
                </div>
            `).join('');
        }
    };

    const updateLunarBirth = (dobId = 'cps-dob', lunarId = 'cps-lunar') => {
        const dob = document.getElementById(dobId)?.value;
        const lunarField = document.getElementById(lunarId);
        if (dob && lunarField) {
            const lunarDate = convertSolarToLunar(dob);
            if (lunarDate) {
                lunarField.value = lunarDate;
            } else {
                UI.toast.warninging("Lunar conversion not available for this date.");
                lunarField.value = '';
            }
        }
    };

    const searchReferrers = async () => {
        try {
            const term = document.getElementById('cps-referrer')?.value.toLowerCase();
            const resultsDiv = document.getElementById('cps-referrer-results');

            if (!term || term.length < 1) {
                if (resultsDiv) resultsDiv.style.display = 'none';
                return;
            }

            const allProspects = (await AppDataStore.getAll('prospects')).filter(p => !p.status || p.status === 'active');
            const allUsers = (await AppDataStore.getAll('users')).filter(u => {
                const lvl = parseInt(u.role?.match(/Level\s+(\d+)/i)?.[1] || 0);
                return lvl >= 3;
            });

            const matchedProspects = allProspects
                .filter(p => (p.full_name && p.full_name.toLowerCase().includes(term)) || (p.nickname && p.nickname.toLowerCase().includes(term)))
                .slice(0, 5);
            const matchedConsultants = allUsers
                .filter(u => u.full_name && u.full_name.toLowerCase().includes(term))
                .slice(0, 5);

            if (resultsDiv) {
                let html = '';

                if (matchedProspects.length > 0) {
                    html += `<div style="padding:4px 10px; font-size:11px; font-weight:600; color:#6b7280; background:#f9fafb; border-bottom:1px solid #e5e7eb; text-transform:uppercase; letter-spacing:0.05em;">Prospects</div>`;
                    html += matchedProspects.map(p => `
                        <div class="search-result-item" onclick="app.selectReferrer(${p.id}, '${(p.full_name || '').replace(/'/g, "\\'")}', 'Prospect')"
                             style="cursor:pointer; padding:8px 12px; border-bottom:1px solid #f3f4f6; display:flex; flex-direction:column;">
                            <strong style="font-size:13px;">${p.full_name || ''}</strong>
                            <span style="font-size:11px; color:#6b7280;">${p.phone || p.ic_number || ''}</span>
                        </div>
                    `).join('');
                }

                if (matchedConsultants.length > 0) {
                    html += `<div style="padding:4px 10px; font-size:11px; font-weight:600; color:#6b7280; background:#f9fafb; border-bottom:1px solid #e5e7eb; text-transform:uppercase; letter-spacing:0.05em;">Consultants</div>`;
                    html += matchedConsultants.map(u => `
                        <div class="search-result-item" onclick="app.selectReferrer(${u.id}, '${(u.full_name || '').replace(/'/g, "\\'")}', 'Consultant')"
                             style="cursor:pointer; padding:8px 12px; border-bottom:1px solid #f3f4f6; display:flex; flex-direction:column;">
                            <strong style="font-size:13px;">${u.full_name || ''}</strong>
                            <span style="font-size:11px; color:#6b7280;">${u.agent_code || u.role || ''}</span>
                        </div>
                    `).join('');
                }

                if (!html) {
                    html = '<div style="padding:10px 12px; color:#6b7280; font-size:13px;">No results found</div>';
                }

                resultsDiv.innerHTML = html;
                resultsDiv.style.display = 'block';
            }
        } catch (error) {
            console.error('Error in searchReferrers:', error);
        }
    };

    const selectReferrer = (id, name, type) => {
        _selectedReferrer = { id, name, type };
        const infoDiv = document.getElementById('cps-referrer-info');
        if (infoDiv) {
            infoDiv.innerHTML = `
                <div class="selected-entity-badge">
                    <span>${type}: <strong>${name}</strong></span>
                    <button class="btn btn-sm secondary" onclick="app.clearSelectedReferrer()">Clear</button>
                </div>
            `;
        }
        const results = document.getElementById('cps-referrer-results');
        if (results) results.style.display = 'none';
        const input = document.getElementById('cps-referrer');
        if (input) input.value = '';
    };

    const clearSelectedReferrer = () => {
        _selectedReferrer = null;
        const infoDiv = document.getElementById('cps-referrer-info');
        if (infoDiv) infoDiv.innerHTML = '';
    };

    // ========== APPOINTMENT CONSULTANT ==========

    const searchConsultants = async () => {
        const term = document.getElementById('consultant-search-input')?.value.toLowerCase().trim();
        const resultsDiv = document.getElementById('consultant-search-results');
        if (!resultsDiv) return;
        if (!term || term.length < 1) { resultsDiv.style.display = 'none'; return; }

        const users = await AppDataStore.getAll('users');
        // Consultants = Level 1–9 (any level user)
        const consultants = users.filter(u => {
            const lvl = parseInt(u.role?.match(/Level\s+(\d+)/i)?.[1] || 0);
            return lvl >= 1 && lvl <= 9;
        });

        const matches = consultants
            .filter(u => u.full_name && u.full_name.toLowerCase().includes(term))
            .filter(u => !_selectedConsultants.find(c => c.id === u.id))
            .slice(0, 10);

        resultsDiv.innerHTML = matches.length
            ? matches.map(u => `
                <div class="search-result-item" onclick="app.selectConsultant(${u.id}, '${(u.full_name||'').replace(/'/g,"\\'")}', '${u.role||''}')" style="cursor:pointer;padding:8px;border-bottom:1px solid #eee;">
                    <strong>${u.full_name}</strong> <span style="font-size:12px;color:#888;">${u.role || ''}</span>
                </div>`).join('')
            : '<div class="search-result-item" style="padding:8px;">No consultants found</div>';
        resultsDiv.style.display = 'block';
    };

    const selectConsultant = (id, name, role) => {
        if (_selectedConsultants.find(c => c.id === id)) return;
        _selectedConsultants.push({ id, name, role, status: 'pending' });
        const input = document.getElementById('consultant-search-input');
        if (input) input.value = '';
        const resultsDiv = document.getElementById('consultant-search-results');
        if (resultsDiv) resultsDiv.style.display = 'none';
        renderSelectedConsultants();
    };

    const removeConsultant = (id) => {
        _selectedConsultants = _selectedConsultants.filter(c => c.id !== id);
        renderSelectedConsultants();
    };

    const renderSelectedConsultants = () => {
        const list = document.getElementById('selected-consultants-list');
        if (!list) return;
        if (_selectedConsultants.length === 0) { list.innerHTML = ''; return; }
        list.innerHTML = _selectedConsultants.map(c => {
            const icon = c.status === 'accepted'
                ? '<i class="fas fa-check-circle" style="color:#16a34a;" title="Accepted"></i>'
                : c.status === 'rejected'
                    ? '<i class="fas fa-times-circle" style="color:#dc2626;" title="Rejected"></i>'
                    : '<i class="fas fa-clock" style="color:#f59e0b;" title="Pending"></i>';
            return `
                <div style="display:flex;align-items:center;justify-content:space-between;padding:6px 10px;background:#fff;border:1px solid var(--gray-200);border-radius:6px;margin-bottom:4px;">
                    <span style="font-size:13px;">${icon} <strong>${c.name}</strong> <span style="color:#888;font-size:11px;">${c.role||''}</span></span>
                    <button class="btn-icon text-danger" onclick="event.stopPropagation();app.removeConsultant(${c.id})" title="Remove"><i class="fas fa-times"></i></button>
                </div>`;
        }).join('');
    };

    // Called by consultant to accept/reject — from notification or activity detail
    const respondConsultantInvite = async (activityId, consultantId, response) => {
        const activity = await AppDataStore.getById('activities', activityId);
        if (!activity) return UI.toast.error('Activity not found');
        const consultants = (activity.consultants || []).map(c =>
            c.id === consultantId ? { ...c, status: response } : c
        );
        await AppDataStore.update('activities', activityId, { consultants });
        UI.toast.success(response === 'accepted' ? 'Appointment accepted!' : 'Appointment rejected.');
        UI.hideModal();
        await viewActivityDetails(activityId);
    };

    const searchProspectReferrers = async () => {
        try {
            const term = document.getElementById('prospect-referrer')?.value.toLowerCase();
            const resultsDiv = document.getElementById('prospect-referrer-results');
            if (!term || term.length < 1) { if (resultsDiv) resultsDiv.style.display = 'none'; return; }

            const allProspects = (await AppDataStore.getAll('prospects')).filter(p => !p.status || p.status === 'active');
            const allUsers = (await AppDataStore.getAll('users')).filter(u => parseInt(u.role?.match(/Level\s+(\d+)/i)?.[1] || 0) >= 3);

            const matchedProspects = allProspects.filter(p => p.full_name?.toLowerCase().includes(term) || p.nickname?.toLowerCase().includes(term)).slice(0, 5);
            const matchedConsultants = allUsers.filter(u => u.full_name?.toLowerCase().includes(term)).slice(0, 5);

            let html = '';
            if (matchedProspects.length) {
                html += `<div style="padding:4px 10px;font-size:11px;font-weight:600;color:#6b7280;background:#f9fafb;border-bottom:1px solid #e5e7eb;text-transform:uppercase;letter-spacing:0.05em;">Prospects</div>`;
                html += matchedProspects.map(p => `<div style="cursor:pointer;padding:8px 12px;border-bottom:1px solid #f3f4f6;" onmousedown="app.selectProspectReferrer(${p.id},'${(p.full_name||'').replace(/'/g,"\\'")}','Prospect')"><strong>${p.full_name}</strong><br><small style="color:#6b7280;">${p.phone||''}</small></div>`).join('');
            }
            if (matchedConsultants.length) {
                html += `<div style="padding:4px 10px;font-size:11px;font-weight:600;color:#6b7280;background:#f9fafb;border-bottom:1px solid #e5e7eb;text-transform:uppercase;letter-spacing:0.05em;">Consultants</div>`;
                html += matchedConsultants.map(u => `<div style="cursor:pointer;padding:8px 12px;border-bottom:1px solid #f3f4f6;" onmousedown="app.selectProspectReferrer(${u.id},'${(u.full_name||'').replace(/'/g,"\\'")}','Consultant')"><strong>${u.full_name}</strong><br><small style="color:#6b7280;">${u.agent_code||u.role||''}</small></div>`).join('');
            }
            if (!html) html = '<div style="padding:10px 12px;color:#6b7280;font-size:13px;">No results found</div>';

            if (resultsDiv) { resultsDiv.innerHTML = html; resultsDiv.style.display = 'block'; }
        } catch (e) { console.error('searchProspectReferrers:', e); }
    };

    const selectProspectReferrer = (id, name, type) => {
        _selectedProspectReferrer = { id, name, type };
        const infoDiv = document.getElementById('prospect-referrer-info');
        // SECURITY: escape user-controlled name/type to prevent XSS (e.g. "<img onerror=...>")
        if (infoDiv) infoDiv.innerHTML = `<div class="selected-entity-badge"><span>${escapeHtml(type)}: <strong>${escapeHtml(name)}</strong></span><button class="btn btn-sm secondary" onclick="app.clearProspectReferrer()">Clear</button></div>`;
        const results = document.getElementById('prospect-referrer-results');
        if (results) results.style.display = 'none';
        const input = document.getElementById('prospect-referrer');
        if (input) input.value = '';
    };

    const clearProspectReferrer = () => {
        _selectedProspectReferrer = null;
        const infoDiv = document.getElementById('prospect-referrer-info');
        if (infoDiv) infoDiv.innerHTML = '';
    };

    const addProspectChildRow = (age = '', gender = '') => {
        const list = document.getElementById('prospect-children-list');
        if (!list) return;
        const row = document.createElement('div');
        row.className = 'prospect-child-row';
        row.style.cssText = 'display:flex;gap:8px;align-items:center;';
        row.innerHTML = `
            <input type="number" min="0" class="form-control prospect-child-age" placeholder="Age" style="max-width:90px;" value="${age}">
            <select class="form-control prospect-child-gender" style="max-width:130px;">
                <option value="">Gender</option>
                <option value="Male" ${gender === 'Male' ? 'selected' : ''}>Male</option>
                <option value="Female" ${gender === 'Female' ? 'selected' : ''}>Female</option>
                <option value="Other" ${gender === 'Other' ? 'selected' : ''}>Other</option>
            </select>
            <button type="button" class="btn-icon text-danger" onclick="this.closest('.prospect-child-row').remove()"><i class="fas fa-trash-alt"></i></button>
        `;
        list.appendChild(row);
    };

    const prefillProspectChildren = (kidsData) => {
        const list = document.getElementById('prospect-children-list');
        if (!list) return;
        list.innerHTML = '';
        let kids = [];
        try { kids = Array.isArray(kidsData) ? kidsData : (kidsData ? JSON.parse(kidsData) : []); } catch(e) { kids = []; }
        kids.forEach(k => addProspectChildRow(k.age || '', k.gender || ''));
    };

    const collectProspectChildren = () => {
        const rows = document.querySelectorAll('#prospect-children-list .prospect-child-row');
        const out = [];
        rows.forEach(r => {
            const age = r.querySelector('.prospect-child-age')?.value?.trim();
            const gender = r.querySelector('.prospect-child-gender')?.value || '';
            if (age || gender) out.push({ age: age ? parseInt(age, 10) : null, gender });
        });
        return out;
    };

    const searchEntities = async () => {
        const searchTerm = document.getElementById('entity-search')?.value.toLowerCase();
        const resultsDiv = document.getElementById('search-results');
        if (!searchTerm || searchTerm.length < 2) {
            if (resultsDiv) resultsDiv.style.display = 'none';
            return;
        }

        const prospects = await getVisibleProspects();
        const customers = await getVisibleCustomers();
        const all = [...prospects.map(p => ({ ...p, type: 'Prospect' })), ...customers.map(c => ({ ...c, type: 'Customer' }))];

        const matches = all.filter(e => e.full_name ? e.full_name.toLowerCase().includes(searchTerm) : false).slice(0, 5);

        if (resultsDiv) {
            resultsDiv.innerHTML = matches.map(m => `
                <div class="search-result-item" onclick="app.selectEntity(${m.id}, '${m.type}')">
                    <strong>${m.full_name}</strong> (${m.type})
                </div>
            `).join('') || '<div class="search-result-item">No results</div>';
            resultsDiv.style.display = 'block';
        }
    };

    const selectEntity = async (id, type) => {
        _selectedEntity = { id, type };
        const entity = type === 'Prospect'
            ? await AppDataStore.getById('prospects', id)
            : await AppDataStore.getById('customers', id);

        const infoDiv = document.getElementById('selected-entity-info');
        if (infoDiv) {
            infoDiv.innerHTML = `
                <div class="selected-entity-badge">
                    <span>${type}: <strong>${entity.full_name}</strong></span>
                    <button class="btn btn-sm secondary" onclick="app.clearSelectedEntity()">Clear</button>
                </div>
             `;
        }
        const sDir = document.getElementById('search-results');
        if (sDir) sDir.style.display = 'none';
        const sInput = document.getElementById('entity-search');
        if (sInput) sInput.value = '';
    };

    const clearSelectedEntity = () => {
        _selectedEntity = null;
        const infoDiv = document.getElementById('selected-entity-info');
        if (infoDiv) infoDiv.innerHTML = '';
    };

    const searchAgents = async () => {
        const term = document.getElementById('co-agent-search-input')?.value.toLowerCase();
        const resultsDiv = document.getElementById('agent-search-results');
        if (!term || term.length < 1) { if (resultsDiv) resultsDiv.style.display = 'none'; return; }

        const consultants = (await AppDataStore.getAll('users')).filter(u => {
            const lvl = parseInt(u.role?.match(/Level\s+(\d+)/i)?.[1] || 0);
            return lvl >= 3 || isAgent(u) || u.role === 'team_leader' || u.role === 'consultant';
        });
        const matches = consultants.filter(u => u.full_name && u.full_name.toLowerCase().includes(term));

        if (resultsDiv) {
            resultsDiv.innerHTML = matches.map(m => `
                <div class="search-result-item" onclick="app.addCoAgent(${m.id}, '${m.full_name.replace(/'/g, "\\'")}')">
                    <strong>${m.full_name}</strong> <span style="color:#888; font-size:11px;">(${m.role || 'Consultant'})</span>
                </div>
            `).join('') || '<div class="search-result-item">No consultants found</div>';
            resultsDiv.style.display = 'block';
        }
    };

    const addCoAgent = (id, name) => {
        if (_selectedCoAgents.length >= 5) {
            UI.toast.warninging('Max 5 co-agents allowed');
            return;
        }
        if (_selectedCoAgents.find(a => a.id === id)) return;

        // Newly-added co-agents start as "pending" so the invitee has to Accept/Reject.
        _selectedCoAgents.push({ id, name, co_role: 'Supporting', status: 'pending' });
        renderCoAgents();
        const aRes = document.getElementById('agent-search-results');
        if (aRes) aRes.style.display = 'none';
        const aInp = document.getElementById('co-agent-search-input');
        if (aInp) aInp.value = '';
    };

    const removeCoAgent = (id) => {
        _selectedCoAgents = _selectedCoAgents.filter(a => a.id !== id);
        renderCoAgents();
    };

    const updateCoAgentRole = (id, role) => {
        const agent = _selectedCoAgents.find(a => a.id === id);
        if (agent) agent.co_role = role;
    };

    const renderCoAgents = () => {
        const container = document.getElementById('selected-co-agents');
        if (container) {
            container.innerHTML = _selectedCoAgents.map(a => {
                // Missing status = legacy entry written before the accept/reject flow — treat as accepted.
                const status = a.status || 'accepted';
                const statusIcon = status === 'accepted'
                    ? '<i class="fas fa-check-circle" style="color:#16a34a;" title="Accepted"></i>'
                    : status === 'rejected'
                        ? '<i class="fas fa-times-circle" style="color:#dc2626;" title="Rejected"></i>'
                        : '<i class="fas fa-clock" style="color:#f59e0b;" title="Pending response"></i>';
                return `
                <div class="co-agent-tag" style="display:inline-flex; align-items:center; gap:8px; padding:6px 12px; margin-bottom:8px;">
                    <span>${statusIcon} ${a.name}</span>
                    <select class="form-control" style="width: auto; padding: 2px 6px; font-size: 11px; height: 24px;" onchange="app.updateCoAgentRole(${a.id}, this.value)">
                        <option value="Supporting" ${a.co_role === 'Supporting' ? 'selected' : ''}>Supporting</option>
                        <option value="Observer" ${a.co_role === 'Observer' ? 'selected' : ''}>Observer</option>
                        <option value="Trainer" ${a.co_role === 'Trainer' ? 'selected' : ''}>Trainer</option>
                    </select>
                    <span class="remove" onclick="app.removeCoAgent(${a.id})" style="cursor:pointer; font-weight:bold; margin-left:4px;">&times;</span>
                </div>
            `;
            }).join('');
        }
    };

    // Called by the invited co-agent to accept/reject an appointment they were assigned to.
    // Updates their entry in activity.co_agents, re-renders the affected views, and notifies
    // the lead agent so the assigner knows the status changed.
    const respondCoAgentInvite = async (activityId, response) => {
        if (!_currentUser || _currentUser.id == null) {
            UI.toast.error('You must be logged in to respond.');
            return;
        }
        if (response !== 'accepted' && response !== 'rejected') {
            UI.toast.error('Invalid response');
            return;
        }
        const activity = await AppDataStore.getById('activities', activityId);
        if (!activity) { UI.toast.error('Activity not found'); return; }
        const coAgents = Array.isArray(activity.co_agents) ? activity.co_agents : [];
        const myEntry = coAgents.find(ca => String(ca.id) === String(_currentUser.id));
        if (!myEntry) { UI.toast.error('You are not a co-agent on this appointment'); return; }

        const updatedCoAgents = coAgents.map(ca =>
            String(ca.id) === String(_currentUser.id)
                ? { ...ca, status: response, responded_at: new Date().toISOString() }
                : ca
        );
        try {
            await AppDataStore.update('activities', activityId, { co_agents: updatedCoAgents });
        } catch (e) {
            UI.toast.error('Could not save response: ' + (e.message || 'Unknown error'));
            return;
        }

        UI.toast.success(response === 'accepted' ? 'Appointment accepted ✓' : 'Appointment rejected');
        // Notify the lead agent so they know the response came in (best-effort, non-blocking).
        _notifyCoAgentResponse({ ...activity, co_agents: updatedCoAgents }, myEntry, response).catch(() => {});

        // Refresh whichever views are currently visible.
        if (document.querySelector('.calendar-view-container')) {
            await renderCalendar();
            await renderTodayActivities();
        }
        // If the activity detail modal is open, re-open it to reflect the new status.
        if (document.querySelector('.modal-overlay.active')) {
            UI.hideModal();
            setTimeout(() => viewActivityDetails(activityId), 150);
        }
    };

    const saveActivity = async (stayOpen = false) => {
        // Re-entrancy guard: blocks double-clicks during the async save flow (file upload,
        // prospect creation, activity creation, referral creation, etc.) which previously
        // allowed 5+ duplicate prospects/activities when the user clicked Save while lagging.
        if (window._savingActivity) { return; }
        window._savingActivity = true;

        // Visually disable every Save button in open modals so the user sees the click landed.
        const saveBtns = Array.from(document.querySelectorAll('.modal-overlay .modal-footer button.primary, .modal .modal-footer button.primary'));
        const _origSaveLabels = saveBtns.map(b => ({ el: b, html: b.innerHTML, disabled: b.disabled }));
        saveBtns.forEach(b => { b.disabled = true; b.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Saving…'; });

        const _releaseSaveGuard = () => {
            window._savingActivity = false;
            _origSaveLabels.forEach(o => { try { o.el.disabled = o.disabled; o.el.innerHTML = o.html; } catch (_) {} });
        };

        try {

        const type = document.getElementById('modal-activity-type')?.value;
        const date = document.getElementById('activity-date')?.value;
        const start = document.getElementById('start-time')?.value;
        const end = document.getElementById('end-time')?.value;

        if (!date || !start || !end) {
            UI.toast.error('Date and time are required.');
            return;
        }

        const venueVal = document.getElementById('activity-venue')?.value || '';
        const activity = {
            activity_type: type,
            activity_date: date,
            start_time: start,
            end_time: end,
            co_agents: _selectedCoAgents,
            consultants: _selectedConsultants,
            lead_agent_id: _currentUser ? _currentUser.id : 5,
            venue: venueVal,
            // Mirror venue to location_address so it persists server-side (the `venue` column
            // may be missing from the Supabase schema and silently stripped on save). For
            // FSA/SITE the type-specific block below will override this with the site address.
            location_address: venueVal || null
        };

        // Venue compulsory for these types
        const venueRequiredTypes = ['CPS', 'FTF', 'EVENT', 'GR', 'XG'];
        if (venueRequiredTypes.includes(type) && !activity.venue) {
            UI.toast.error('Venue is required for ' + type + '. Please select a venue.');
            return;
        }

        if (type === 'CPS') {
            const name = document.getElementById('cps-name')?.value;
            const phone = document.getElementById('cps-phone')?.value;
            const relation = document.getElementById('cps-relationship')?.value;
            const referrerInputName = document.getElementById('cps-referrer')?.value.trim();

            // All CPS must have a referrer — business runs by recommendation only
            if (!_selectedReferrer) {
                UI.toast.error('A referrer is required. All appointments must be by recommendation. Search and select the person who referred this prospect.');
                return;
            }

            if (!name || !phone) {
                UI.toast.error('Name and Phone are required for CPS.');
                return;
            }
            if (!relation) {
                UI.toast.error('Relation is required for CPS.');
                return;
            }

            // Duplicate checking: BLOCK on same name+phone or same name+IC
            {
                const allPeople = [...(await AppDataStore.getAll('prospects')), ...(await AppDataStore.getAll('customers'))];
                const normalize = str => str ? str.toLowerCase().replace(/\s+/g, '') : '';
                const normName = normalize(name);
                const ic = document.getElementById('cps-ic')?.value?.trim();

                const hardDuplicate = allPeople.find(p => {
                    const sameName = normalize(p.full_name) === normName;
                    if (!sameName) return false;
                    if (phone && p.phone && normalize(p.phone) === normalize(phone)) return true;
                    if (ic && p.ic_number && normalize(p.ic_number) === normalize(ic)) return true;
                    return false;
                });

                if (hardDuplicate) {
                    const agent = await AppDataStore.getById('users', hardDuplicate.responsible_agent_id || hardDuplicate.lead_agent_id) || { full_name: 'Unknown Agent' };
                    const matchField = (phone && hardDuplicate.phone && normalize(hardDuplicate.phone) === normalize(phone)) ? 'phone number' : 'IC number';
                    UI.toast.error(`Duplicate blocked: "${hardDuplicate.full_name}" already exists under ${agent.full_name} with the same name and ${matchField}.`);
                    return;
                }

                // Soft warning: same phone or same name (but not hard match)
                if (!window._cpsDuplicateConfirmed) {
                    const softDuplicate = allPeople.find(p => normalize(p.phone) === normalize(phone) || normalize(p.full_name) === normName);
                    if (softDuplicate) {
                        const agent = await AppDataStore.getById('users', softDuplicate.responsible_agent_id || softDuplicate.lead_agent_id) || { full_name: 'Unknown Agent' };
                        const activities2 = (await AppDataStore.getAll('activities')).filter(a => a.prospect_id === softDuplicate.id || a.customer_id === softDuplicate.id);
                        activities2.sort((a, b) => new Date(b.activity_date) - new Date(a.activity_date));
                        const lastDate = activities2.length > 0 ? activities2[0].activity_date : 'N/A';
                        const msg = `This person may have visited before. The agent is ${agent.full_name}, last meet up on ${lastDate}. Are you sure this is not the same prospect? Check with your leader.`;
                        UI.showModal('Potential Duplicate Found', `<p>${msg}</p>`, [
                            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
                            { label: 'Continue Anyway', type: 'primary', action: `window._cpsDuplicateConfirmed = true; (async () => { await app.saveActivity(${stayOpen}); })()` }
                        ]);
                        return;
                    }
                }
            }
            window._cpsDuplicateConfirmed = false; // reset flag

            // All Basic Info fields pulled via the shared collector — keeps
            // CPS + Prospect forms in lockstep. Activity-specific metadata
            // (responsible_agent_id, referred_by_*, score) is merged after.
            const basic = collectBasicInfoData('cps');
            const prospectData = {
                ...basic,
                score: SCORING_RULES.CREATE_PROSPECT,
                responsible_agent_id: _currentUser?.id || null,
                referred_by_id: _selectedReferrer?.id || null,
                referred_by_type: _selectedReferrer?.type || null,
                referred_by: _selectedReferrer?.name || document.getElementById('cps-referrer')?.value || '',
            };

            let prospect;
            try {
                prospect = await AppDataStore.create('prospects', prospectData);
            } catch (err) {
                UI.toast.error('Failed to create prospect: ' + (err.message || 'Unknown error'));
                return;
            }
            activity.prospect_id = prospect.id;
            activity.activity_title = `CPS With ${name}`;

            // Auto-create referral record from CPS activity
            const _refType = (_selectedReferrer.type || '').toLowerCase() === 'consultant' ? 'user' : 'prospect';
            try {
                await AppDataStore.create('referrals', {
                    id: Date.now(),
                    referrer_id: _selectedReferrer.id,
                    referrer_type: _refType,
                    referred_prospect_id: prospect.id,
                    referral_source: 'CPS',
                    memo: '',
                    is_converted: false,
                    status: 'Pending',
                    created_at: new Date().toISOString()
                });
            } catch(e) { console.warn('Auto-referral creation failed:', e); }

            const inviteMethod = document.getElementById('cps-invitation-method')?.value;
            activity.cps_invitation_method = inviteMethod === 'Other' ? document.getElementById('cps-invitation-other')?.value : inviteMethod;
            activity.cps_invitation_details = document.getElementById('cps-invitation-details')?.value || '';
            activity.summary = document.getElementById('cps-summary')?.value?.trim() || '';
        } else if (type === 'FSA' || type === 'SITE') {
            const address = document.getElementById('location-address')?.value;
            if (!address) {
                UI.toast.error('Address is required for site visits.');
                return;
            }
            activity.location_address = address;
            activity.activity_title = type === 'FSA' ? 'Feng Shui Analysis' : 'Site Visit';
        } else if (type === 'EVENT' || type === 'AGENT_MEETING' || type === 'AGENT_TRAINING') {
            const visibility = document.querySelector('input[name="event-visibility"]:checked')?.value || 'closed';
            const eventId = document.getElementById('existing-event')?.value;
            if (!eventId) {
                UI.toast.error('Please select an event. Use "Create New" to add one first.');
                return;
            }
            const ev = await AppDataStore.getById('events', eventId);
            activity.activity_title = ev ? (ev.event_title || ev.title) : 'Event';
            activity.event_id = parseInt(eventId);
            activity.visibility = visibility;

            // Link to selected entity if present
            if (_selectedEntity) {
                if (_selectedEntity.type === 'Prospect') activity.prospect_id = _selectedEntity.id;
                else activity.customer_id = _selectedEntity.id;
            }

            // Attendees saved after activity is created (below) so activity_id is available
        } else {
            if (!_selectedEntity) {
                UI.toast.error('Please select a prospect or customer.');
                return;
            }
            activity.activity_title = document.getElementById('meeting-title')?.value || 'Meeting';
            if (_selectedEntity.type === 'Prospect') activity.prospect_id = _selectedEntity.id;
            else activity.customer_id = _selectedEntity.id;
        }

        if (document.getElementById('is-closing')?.checked) {
            activity.is_closing = true;
            activity.solution_sold = document.getElementById('solution-sold')?.value;
            activity.amount_closed = document.getElementById('amount-closed')?.value;
            activity.payment_method = document.getElementById('payment-method')?.value;
            activity.invoice_number = document.getElementById('invoice-number')?.value;
            activity.collection_date = document.getElementById('collection-date')?.value;
            const imgInput = document.getElementById('redemption-image');
            if (imgInput && imgInput.files.length > 0) activity.redemption_image_name = imgInput.files[0].name;

            if (activity.payment_method === 'POP') {
                const amount = document.getElementById('pop-monthly-amount')?.value;
                const tenure = document.getElementById('pop-tenure')?.value;
                const downPayment = document.getElementById('pop-down-payment')?.value;
                if (amount) activity.pop_monthly_amount = amount;
                if (tenure) activity.pop_tenure = tenure;
                if (downPayment) activity.pop_down_payment = downPayment;
            }
        }

        if (document.getElementById('unable-to-serve')?.checked) {
            activity.unable_to_serve = true;
            activity.unable_reason = document.getElementById('unable-reason')?.value;
        }

        if (document.getElementById('continue-follow-up')?.checked) {
            activity.continue_follow_up = true;
        }

        activity.summary = document.getElementById('note-key-points')?.value || '';
        activity.note_key_points = document.getElementById('note-key-points')?.value || '';
        activity.note_outcome = document.getElementById('note-outcome')?.value || '';
        activity.note_next_steps = document.getElementById('note-next-steps')?.value || '';
        activity.note_needs = document.getElementById('note-needs')?.value || '';
        activity.note_pain_points = document.getElementById('note-pain-points')?.value || '';

        // CPS attachment upload — store the file in Supabase storage so it's viewable everywhere.
        // We stash it here and upload AFTER the activity row exists so the path can reference the activity id.
        let _pendingCpsFile = null;
        if (type === 'CPS') {
            const attInput = document.getElementById('cps-attachment');
            if (attInput && attInput.files.length > 0) {
                const file = attInput.files[0];
                if (file.size > 5 * 1024 * 1024) {
                    UI.toast.error('File size exceeds 5MB limit');
                    return;
                }
                _pendingCpsFile = file;
            }
        }

        let savedActivity;
        try {
            savedActivity = await AppDataStore.create('activities', activity);
        } catch (err) {
            UI.toast.error('Failed to save activity: ' + (err.message || 'Unknown error'));
            return;
        }

        // Upload CPS attachment to Supabase storage and save URL into activities.photo_urls.
        // Kept non-blocking for the rest of the save flow — errors show a toast but don't fail the activity.
        if (_pendingCpsFile && savedActivity?.id) {
            try {
                const sb = window.supabase || window.supabaseClient;
                if (sb && sb.storage) {
                    const safeName = _pendingCpsFile.name.replace(/[^a-zA-Z0-9._-]/g, '_');
                    const path = `activity_photos/${savedActivity.id}_${Date.now()}_${safeName}`;
                    const { error: upErr } = await sb.storage.from('attachments').upload(path, _pendingCpsFile, { upsert: false, contentType: _pendingCpsFile.type });
                    if (upErr) throw upErr;
                    const { data: urlData } = sb.storage.from('attachments').getPublicUrl(path);
                    if (urlData?.publicUrl) {
                        const existing = Array.isArray(savedActivity.photo_urls) ? savedActivity.photo_urls : [];
                        await AppDataStore.update('activities', savedActivity.id, { photo_urls: [...existing, urlData.publicUrl] });
                        savedActivity.photo_urls = [...existing, urlData.publicUrl];
                    }
                } else {
                    UI.toast.error('CPS attachment not uploaded — Supabase not connected');
                }
            } catch (err) {
                console.error('CPS attachment upload failed:', err);
                UI.toast.error('CPS attachment upload failed: ' + (err.message || 'Unknown error'));
            }
        }

        // Save event attendees now that we have the activity ID — stored per-activity so
        // different dates of the same event don't share attendees
        if ((type === 'EVENT' || type === 'AGENT_MEETING' || type === 'AGENT_TRAINING') && _selectedAttendees.length > 0) {
            for (const att of _selectedAttendees) {
                await AppDataStore.create('event_attendees', {
                    event_id: activity.event_id,
                    activity_id: savedActivity.id,
                    entity_id: att.id,
                    entity_name: att.name || att.full_name || '',
                    attendee_id: att.id,
                    attendee_type: att.type,
                    attendance_status: att.status,
                    added_by_agent_id: _currentUser?.id || null,
                    added_by_name: _currentUser?.full_name || ''
                });
            }
        }

        if (document.getElementById('is-closing')?.checked) {
            const salesIdea = document.getElementById('case-sales-idea')?.value;
            const planDetails = document.getElementById('case-plan-details')?.value;
            const successStory = document.getElementById('case-success-story')?.value;

            if (salesIdea || planDetails || successStory) {
                try {
                    await AppDataStore.create('case_studies', {
                        title: `Case Study: ${activity.activity_title}`,
                        prospect_id: activity.prospect_id || null,
                        customer_id: activity.customer_id || null,
                        activity_id: savedActivity.id,
                        sales_idea: salesIdea,
                        plan_details: planDetails,
                        success_story: successStory,
                        product: activity.solution_sold,
                        amount: activity.amount_closed,
                        closing_date: activity.activity_date,
                        created_by: _currentUser?.id || null,
                        is_public: false
                    });
                } catch (err) {
                    console.warn('Case study save failed:', err.message);
                }
            }
        }

        // Auto-create CPS Invitation Case in Success Case Library
        if (type === 'CPS') {
            try {
                await AppDataStore.create('case_studies', {
                    title: `CPS: ${activity.activity_title}`,
                    prospect_id: activity.prospect_id || null,
                    customer_id: null,
                    activity_id: savedActivity.id,
                    case_type: 'cps',
                    cps_invitation_method: activity.cps_invitation_method || '',
                    cps_invitation_details: activity.cps_invitation_details || '',
                    closing_date: activity.activity_date,
                    created_by: _currentUser?.id || null,
                    is_public: false
                });
            } catch (err) {
                console.warn('CPS case study auto-create failed:', err.message);
            }
        }

        UI.toast.success('Activity saved!');

        // === If this save was approving a CPS intake request, mark it approved ===
        let _cpsIntakeWaCallback = null;
        if (_pendingIntakeId) {
            const intakeRow = _pendingIntakeRow;
            try {
                await AppDataStore.update('cps_intake_requests', _pendingIntakeId, {
                    status: 'approved',
                    approved_at: new Date().toISOString(),
                    approved_activity_id: savedActivity?.id || null
                });
            } catch (e) { console.warn('CPS intake approval mark failed:', e); }
            _pendingIntakeId  = null;
            _pendingIntakeRow = null;

            // Build WhatsApp modal — will be shown AFTER activity modal closes
            if (intakeRow?.prospect_phone) {
                const phone   = intakeRow.prospect_phone.replace(/\D/g, '');
                const name    = intakeRow.prospect_name  || 'Pelanggan';
                const date    = intakeRow.activity_date  || '';
                const start   = (intakeRow.start_time    || '').slice(0, 5);
                const end     = (intakeRow.end_time      || '').slice(0, 5);
                const venue   = intakeRow.venue_name     || '';
                const address = intakeRow.venue_address  || '';
                const waze    = intakeRow.waze_link      || '';

                const mbbHqNote = (venue || '').toLowerCase().includes('mbb hq') ? [
                    ``,
                    `___________________________________________`,
                    `给予第一次来DC-KL总部的朋友`,
                    `欢迎您`,
                    ``,
                    `1. 驾车的朋友，可以Park 在B1-basement parking。`,
                    `2. 搭monorail 的朋友，请下Bukit Nanas station。走向Menara Bangkok Bank 方向`,
                    `3. 到了时，请打电话给我。因为需要亲自来接您才可以上楼。`,
                    `4. 在等待的时候，请到保安柜台登记。 告知是去 21 楼 DC，需用到IC`,
                ] : [];

                const msg = [
                    `\u2705 Your appointment has been CONFIRMED! / 您的预约已确认！`,
                    ``,
                    `\u{1F464} ${name}`,
                    `\u{1F4C5} Date / 日期: ${date}`,
                    `\u23F0 Time / 时间: ${start}–${end}`,
                    venue   ? `\u{1F4CD} Venue / 地点: ${venue}` : '',
                    address ? `\u{1F3E0} Address / 地址: ${address}` : '',
                    waze    ? `\u{1F5FA}\uFE0F Waze: ${waze}` : '',
                    ``,
                    `Please ensure you arrive on time. Dress code: formal/smart casual.`,
                    `请准时出席。着装要求：正式/整洁休闲。`,
                    ...mbbHqNote,
                ].filter(l => l !== undefined && !(l === '' && false)).join('\n').replace(/\n{3,}/g, '\n\n').trim();

                const waUrl = `https://wa.me/${phone}?text=${encodeURIComponent(msg)}`;

                _cpsIntakeWaCallback = () => {
                    UI.showModal(
                        '✅ Appointment Confirmed',
                        `<div style="text-align:center; padding:8px 0;">
                            <p style="margin-bottom:12px; font-size:14px; color:#374151;">
                                Notify <strong>${name}</strong> (${intakeRow.prospect_phone}) via WhatsApp?
                            </p>
                            <pre style="background:#f3f4f6; border-radius:8px; padding:12px; font-size:12px; text-align:left; white-space:pre-wrap; max-height:220px; overflow-y:auto;">${msg}</pre>
                        </div>`,
                        [
                            { label: '📲 Send WhatsApp', type: 'primary',   action: `window.open('${waUrl}', '_blank'); UI.hideModal();` },
                            { label: 'Skip',              type: 'secondary', action: 'UI.hideModal();' }
                        ]
                    );
                };
            }
        }

        // === Push notification fan-out (non-blocking, best-effort) ===
        _notifyActivityCreated(savedActivity || activity).catch(() => {});

        // === Auto Scoring: Award points based on activity type ===
        try {
            await applyActivityScoring(activity);
        } catch (e) { console.warn('Activity scoring failed:', e); }

        // === Auto Protection Extension: Extend deadline based on activity type ===
        if (activity.prospect_id) {
            try {
                const extType = activity.is_closing ? 'transaction' : getExtensionType(activity.activity_type);
                await autoExtendProtection(activity.prospect_id, extType);
            } catch (e) { console.warn('Protection auto-extend failed:', e); }
        }

        // === Workflow Engine: Trigger activity_completed workflows ===
        try {
            const entityName = _selectedEntity?.name || activity.activity_title || '';
            await executeWorkflows('activity_completed', { name: entityName, activityType: activity.activity_type });
        } catch (e) { console.warn('Workflow trigger failed:', e); }

        // === Auto Milestone: Mark milestone based on activity type / title ===
        try {
            if (_currentUser) {
                const aType = activity.activity_type || '';
                const aTitle = (activity.activity_title || '').toLowerCase();
                const milestoneMap = [
                    { key: 'CPS',           test: () => aType === 'CPS' },
                    { key: '9 Stars',       test: () => aTitle.includes('9 star') || aTitle.includes('nine star') },
                    { key: 'DIY',           test: () => aTitle.includes('diy') },
                    { key: '福气课',         test: () => aTitle.includes('福气') || aTitle.includes('fudi') || aTitle.includes('fu qi') },
                    { key: '九运课',         test: () => aTitle.includes('九运') || aTitle.includes('jiuyun') || aTitle.includes('jiu yun') },
                    { key: 'Museum',        test: () => aTitle.includes('museum') },
                    { key: 'HuiJi',         test: () => aTitle.includes('huiji') || aTitle.includes('hui ji') },
                    { key: 'Advance Class', test: () => aTitle.includes('advance') },
                    { key: 'Sharing',       test: () => aTitle.includes('sharing') || aType === 'Sharing' }
                ];
                for (const m of milestoneMap) {
                    if (m.test()) await markMilestoneCompleted(_currentUser.id, m.key);
                }
            }
        } catch (e) { console.warn('Milestone auto-mark failed:', e); }

        // === Follow-Up Automation: trigger CPS-based follow-ups (data-driven, non-blocking) ===
        if (activity.activity_type === 'CPS' && activity.prospect_id) {
            dispatchAfterCpsTriggers(activity.prospect_id).catch(e => console.warn('CPS follow-up triggers failed:', e));
        }

        await renderCalendar();
        await renderFollowUpReminders();
        await renderTodayActivities();

        // === Auto-refresh open activity tabs so changes reflect immediately ===
        try {
            const pid = activity.prospect_id;
            const cid = activity.customer_id;
            if (pid) {
                const bodyEl = document.getElementById(`acc-body-activity-${pid}`);
                if (bodyEl && bodyEl.style.display !== 'none') {
                    await switchProspectTab('activity', pid, null, bodyEl);
                }
            }
            if (cid) {
                const bodyEl = document.getElementById(`cust-acc-body-activity-${cid}`);
                if (bodyEl && bodyEl.style.display !== 'none') {
                    const cust = await AppDataStore.getById('customers', cid);
                    if (cust) await renderCustomerActivityTab(cust, bodyEl.id);
                }
            }
        } catch (e) { console.warn('Activity tab auto-refresh failed:', e); }

        if (!stayOpen) {
            UI.hideModal();
            if (_cpsIntakeWaCallback) setTimeout(_cpsIntakeWaCallback, 300);
        } else {
            // Reset co-agents and consultants when staying open for another add
            _selectedCoAgents = [];
            _selectedConsultants = [];
            await openActivityModal(date);
        }
        } finally {
            _releaseSaveGuard();
        }
    };

    const saveAndAddAnother = async () => await saveActivity(true);

    // ========== PUSH NOTIFICATIONS: notify subscribed users when an activity is created ==========
    // Fire-and-forget: never blocks the save flow, never throws.
    // Targets = lead_agent + co_agents + admins/team leads, minus the creator themselves.
    const _notifyActivityCreated = async (savedActivity) => {
        try {
            if (!savedActivity || !window.PushNotif) return;
            const targets = new Set();
            if (savedActivity.lead_agent_id != null) targets.add(String(savedActivity.lead_agent_id));
            if (Array.isArray(savedActivity.co_agents)) {
                // co_agents is an array of {id, name, co_role, status} objects — not raw IDs.
                // The previous version iterated each object as if it were an ID and pushed
                // "[object Object]" into the targets set, so co-agents never got notified.
                savedActivity.co_agents.forEach(ca => {
                    if (ca && ca.id != null) targets.add(String(ca.id));
                });
            }
            // Include admins / team leads so management sees new activity across the org.
            try {
                const allUsers = await AppDataStore.getAll('users');
                (allUsers || []).forEach(u => {
                    const role = (u.role || '').toString().toLowerCase();
                    const lvlMatch = role.match(/level\s*(\d+)/);
                    const lvl = lvlMatch ? parseInt(lvlMatch[1]) : 99;
                    const isLead =
                        lvl <= 4 ||
                        role === 'team_leader' ||
                        role === 'admin' ||
                        role === 'super_admin' ||
                        role === 'marketing_manager' ||
                        role === 'manager';
                    if (isLead && u.id != null) targets.add(String(u.id));
                });
            } catch (e) { /* admin broadcast is best-effort */ }

            // Don't self-notify the creator — they just did it.
            if (_currentUser && _currentUser.id != null) targets.delete(String(_currentUser.id));
            if (targets.size === 0) return;

            const whoLabel = _currentUser
                ? (_currentUser.full_name || _currentUser.name || _currentUser.email || 'Someone')
                : 'Someone';
            const typeLabel = savedActivity.activity_type || savedActivity.type || 'Activity';
            const titleLabel = savedActivity.activity_title || savedActivity.title || savedActivity.subject || '';
            const dateLabel = savedActivity.activity_date || savedActivity.date || '';

            await window.PushNotif.sendActivityPush(
                savedActivity,
                Array.from(targets),
                {
                    title: `New ${typeLabel} scheduled`,
                    body: `${whoLabel}: ${titleLabel}${dateLabel ? ` (${dateLabel})` : ''}`,
                    url: `./index.html#calendar`,
                }
            );
        } catch (e) {
            // Never let notification errors affect the activity save flow.
            console.warn('[PushNotif] notifyActivityCreated failed:', e);
        }
    };

    // Notify only specific co-agents (delta case: someone was added to an existing activity).
    // Uses the same Edge Function as _notifyActivityCreated so all push infra is shared.
    const _notifyCoAgentAdded = async (savedActivity, newCoAgentIds) => {
        try {
            if (!savedActivity || !window.PushNotif) return;
            if (!Array.isArray(newCoAgentIds) || newCoAgentIds.length === 0) return;
            const targets = newCoAgentIds
                .filter(id => id != null)
                .map(String)
                .filter(id => !_currentUser || String(_currentUser.id) !== id);
            if (targets.length === 0) return;

            const whoLabel = _currentUser
                ? (_currentUser.full_name || _currentUser.name || _currentUser.email || 'Someone')
                : 'Someone';
            const typeLabel = savedActivity.activity_type || 'Activity';
            const dateLabel = savedActivity.activity_date || '';
            const timeLabel = savedActivity.start_time || '';

            await window.PushNotif.sendActivityPush(
                savedActivity,
                targets,
                {
                    title: `You've been invited to a ${typeLabel}`,
                    body: `${whoLabel} added you as co-agent${dateLabel ? ` on ${dateLabel}${timeLabel ? ` at ${timeLabel}` : ''}` : ''}. Tap to accept or reject.`,
                    url: `./index.html#calendar`,
                }
            );
        } catch (e) {
            console.warn('[PushNotif] notifyCoAgentAdded failed:', e);
        }
    };

    // Notify the lead agent when a co-agent accepts or rejects their invitation.
    const _notifyCoAgentResponse = async (savedActivity, coAgent, response) => {
        try {
            if (!savedActivity || !window.PushNotif || !coAgent) return;
            const leadId = savedActivity.lead_agent_id;
            if (leadId == null) return;
            // Don't self-notify — e.g. lead agent responding to an invite on their own activity.
            if (_currentUser && String(_currentUser.id) === String(leadId)) return;

            const typeLabel = savedActivity.activity_type || 'Activity';
            const dateLabel = savedActivity.activity_date || '';
            const timeLabel = savedActivity.start_time || '';
            const verb = response === 'accepted' ? 'accepted' : 'rejected';

            await window.PushNotif.sendActivityPush(
                savedActivity,
                [String(leadId)],
                {
                    title: `Co-agent ${verb} your ${typeLabel}`,
                    body: `${coAgent.name || 'Co-agent'} ${verb} the invitation${dateLabel ? ` on ${dateLabel}${timeLabel ? ` at ${timeLabel}` : ''}` : ''}.`,
                    url: `./index.html#calendar`,
                }
            );
        } catch (e) {
            console.warn('[PushNotif] notifyCoAgentResponse failed:', e);
        }
    };

    // ========== AUTO-SUBSCRIBE PUSH for PWA / homescreen users ==========
    const _autoSubscribePush = () => {
        try {
            if (!window.PushNotif || !window.PushNotif.isPushSupported()) return;
            // Only auto-prompt for installed PWA (homescreen) — not regular browser tabs
            const isStandalone = window.matchMedia('(display-mode: standalone)').matches
                || window.navigator.standalone === true;
            if (!isStandalone) return;
            // Delay so login UI settles first, then verify + subscribe if needed
            setTimeout(async () => {
                try {
                    // Even if push_enabled=1, verify the browser subscription still exists.
                    // The Edge Function prunes expired endpoints from the DB, but the
                    // localStorage flag stays set — causing silent notification failures.
                    if (localStorage.getItem('push_enabled') === '1') {
                        const reg = window._swRegistration || (await navigator.serviceWorker.ready);
                        const existingSub = reg && (await reg.pushManager.getSubscription());
                        if (existingSub) return; // still active, nothing to do
                        // Subscription was lost — clear flag and re-subscribe below
                        localStorage.removeItem('push_enabled');
                        console.log('[Push] stale push_enabled flag cleared — re-subscribing');
                    }
                    await window.PushNotif.subscribe();
                } catch (e) { console.warn('[Push] auto-subscribe skipped:', e.message || e); }
            }, 2000);
        } catch (_) {}
    };

    // ========== PUSH NOTIFICATION: notify when a 福运相随 highlight is created/updated ==========
    const _notifyHighlightSaved = async (highlight, isNew) => {
        try {
            if (!highlight || !window.PushNotif) return;
            const targets = new Set();
            // Notify all active users
            try {
                const allUsers = await AppDataStore.getAll('users');
                (allUsers || []).forEach(u => {
                    if (u.id != null && u.status !== 'inactive') targets.add(String(u.id));
                });
            } catch (_) {}
            // Don't self-notify the author
            if (_currentUser && _currentUser.id != null) targets.delete(String(_currentUser.id));
            if (targets.size === 0) return;

            const typeMap = { highlight: '📰 Highlight', success_story: '🌟 Success Story', recommendation_tip: '💡 Tip' };
            const typeLabel = typeMap[highlight.type] || 'Highlight';

            await window.PushNotif.sendActivityPush(
                highlight,
                Array.from(targets),
                {
                    title: isNew ? `福运相随: New ${typeLabel}` : `福运相随: ${typeLabel} Updated`,
                    body: highlight.title || '',
                    url: './index.html#fude',
                }
            );
        } catch (e) {
            console.warn('[PushNotif] notifyHighlightSaved failed:', e);
        }
    };

    // ========== PAST RECORD ENTRY (for old customers with historical meet ups) ==========
    const openPastRecordModal = async (prospectId) => {
        const prospect = await AppDataStore.getById('prospects', prospectId);
        if (!prospect) {
            UI.toast.error('Prospect not found.');
            return;
        }

        const today = new Date().toISOString().split('T')[0];
        const modalContent = `
            <div class="activity-modal-form">
                <p style="background:#fff8e1;border:1px solid #ffe082;color:#7a5c00;padding:10px 12px;border-radius:6px;font-size:13px;margin-bottom:14px;">
                    <i class="fas fa-history"></i> Log a historical meet up for <strong>${prospect.full_name}</strong>. This entry will <strong>not</strong> award scoring points or extend protection — it is only for record keeping.
                </p>
                <div class="form-row">
                    <div class="form-group half">
                        <label>Date <span class="required">*</span></label>
                        <input type="date" id="past-record-date" class="form-control" max="${today}">
                    </div>
                    <div class="form-group half">
                        <label>Activity Type <span class="required">*</span></label>
                        <select id="past-record-type" class="form-control">
                            <option value="CPS">CPS - Consultation/Planning Session</option>
                            <option value="FTF">FTF - Face to Face Meeting</option>
                            <option value="FSA">FSA - Feng Shui Analysis</option>
                            <option value="GR">GR - Golden Road</option>
                            <option value="XG">XG - Xin Gua</option>
                            <option value="SITE">Site Visit</option>
                            <option value="CALL">Call</option>
                            <option value="EMAIL">Email</option>
                            <option value="WHATSAPP">WhatsApp</option>
                        </select>
                    </div>
                </div>
                <div class="form-group">
                    <label>Title</label>
                    <input type="text" id="past-record-title" class="form-control" placeholder="e.g. House FSA visit">
                </div>
                <div class="form-group">
                    <label>Core Problem / Summary</label>
                    <textarea id="past-record-summary" class="form-control" rows="3" placeholder="What was discussed or done during this meet up?"></textarea>
                </div>
                <div class="form-group">
                    <label>Outcome</label>
                    <textarea id="past-record-outcome" class="form-control" rows="2" placeholder="What was the result?"></textarea>
                </div>
                <div class="form-group">
                    <label>Next Action</label>
                    <input type="text" id="past-record-next" class="form-control" placeholder="Optional follow up note">
                </div>
            </div>
        `;
        UI.showModal('Add Past Record', modalContent, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: 'Save Past Record', type: 'primary', action: `(async () => { await app.savePastRecord(${prospectId}); })()` }
        ]);
    };

    const savePastRecord = async (prospectId) => {
        const date = document.getElementById('past-record-date')?.value;
        const type = document.getElementById('past-record-type')?.value;
        const title = document.getElementById('past-record-title')?.value?.trim() || '';
        const summary = document.getElementById('past-record-summary')?.value?.trim() || '';
        const outcome = document.getElementById('past-record-outcome')?.value?.trim() || '';
        const nextAction = document.getElementById('past-record-next')?.value?.trim() || '';

        if (!date) {
            UI.toast.error('Date is required.');
            return;
        }
        if (!type) {
            UI.toast.error('Activity type is required.');
            return;
        }

        const activity = {
            prospect_id: prospectId,
            activity_type: type,
            activity_date: date,
            activity_title: title || `${type} (Past Record)`,
            summary: summary,
            core_problem: summary,
            note_outcome: outcome,
            note_next_steps: nextAction,
            next_action: nextAction,
            is_past_record: true,
            lead_agent_id: _currentUser ? _currentUser.id : null,
            co_agents: [],
            consultants: []
        };

        let savedPastRecord;
        try {
            savedPastRecord = await AppDataStore.create('activities', activity);
        } catch (err) {
            UI.toast.error('Failed to save past record: ' + (err.message || 'Unknown error'));
            return;
        }

        UI.toast.success('Past record saved.');

        // === Push notification fan-out (non-blocking, best-effort) ===
        _notifyActivityCreated(savedPastRecord || activity).catch(() => {});
        UI.hideModal();

        const bodyEl = document.getElementById(`acc-body-activity-${prospectId}`);
        if (bodyEl) {
            await switchProspectTab('activity', prospectId, null, bodyEl);
        }
    };

    // ========== PHASE 3: PROSPECT MANAGEMENT FUNCTIONS ==========

    let _sortField = 'score';
    let _sortDirection = 'desc';
    // ── Pagination state for prospects table ──
    let _prospectPage = 0;
    const _prospectPageSize = 50;

    const sortProspects = async (field) => {
        if (_sortField === field) {
            _sortDirection = _sortDirection === 'asc' ? 'desc' : 'asc';
        } else {
            _sortField = field;
            _sortDirection = 'desc';
        }
        _prospectPage = 0; // reset to first page on sort change
        await renderProspectsTable();
    };

    const showProspectsView = async (container) => {
        container.innerHTML = `
            <div class="prospects-view">
                <div class="tab-navigation">
                    <button class="tab-btn active" onclick="app.switchCustomerTab('prospects')">Prospects</button>
                    <button class="tab-btn" onclick="app.switchCustomerTab('customers')">Customers</button>
                </div>

                <div id="prospects-tab-content">
                    <div class="prospects-header">
                        <div>
                            <h1>Prospects Management</h1>
                            <p>Track and manage potential customers through the lifecycle.</p>
                        </div>
                        <div class="header-actions">
                            <button class="btn secondary" onclick="app.openImportWizard()">
                                <i class="fas fa-file-import"></i> Bulk Import
                            </button>
                            <button class="btn primary" onclick="app.openAddProspectModal()">
                                <i class="fas fa-plus"></i> Add Prospect
                            </button>
                        </div>
                    </div>

                <div class="filter-bar">
                    <div style="display:flex;gap:8px;align-items:center;">
                        <div class="search-group" style="flex:1;">
                            <i class="fas fa-search"></i>
                            <input type="text" id="prospect-search" placeholder="Search by name, phone, email, or ID..." oninput="app.debounceCall('prospect-search', app.filterProspects, 220)">
                        </div>
                        <button class="btn secondary btn-sm" onclick="(function(btn){var p=document.getElementById('prospect-adv-filters');var open=p.style.display!=='none';p.style.display=open?'none':'block';btn.innerHTML=open?'<i class=\\'fas fa-sliders-h\\'></i> Filters':'<i class=\\'fas fa-sliders-h\\'></i> Filters <i class=\\'fas fa-chevron-up\\'></i>';})(this)" style="white-space:nowrap;"><i class="fas fa-sliders-h"></i> Filters</button>
                    </div>
                    <div id="prospect-adv-filters" style="display:none;margin-top:10px;">
                        <div class="filter-group">
                            <select id="filter-score" onchange="app.filterProspects()">
                                <option value="">All Scores</option>
                                <option value="A+">Grade A+ (800-1000)</option>
                                <option value="A">Grade A (600-799)</option>
                                <option value="B">Grade B (400-599)</option>
                                <option value="C">Grade C (200-399)</option>
                                <option value="D">Grade D (0-199)</option>
                            </select>
                            <select id="filter-gua" onchange="app.filterProspects()">
                                <option value="">All Ming Gua</option>
                                <option value="MG1">MG1 坎</option>
                                <option value="MG2">MG2 坤</option>
                                <option value="MG3">MG3 震</option>
                                <option value="MG4">MG4 巽</option>
                                <option value="MG5">MG5</option>
                                <option value="MG6">MG6 乾</option>
                                <option value="MG7">MG7 兑</option>
                                <option value="MG8">MG8 艮</option>
                                <option value="MG9">MG9 离</option>
                            </select>
                            <select id="filter-status" onchange="app.filterProspects()">
                                <option value="">All Status</option>
                                <option value="active">Active</option>
                                <option value="attention">Needs Attention</option>
                                <option value="reassign">Reassignable</option>
                                <option value="critical">Critical</option>
                            </select>
                            <select id="filter-agent" onchange="app.filterProspects()">
                                <option value="">All Agents</option>
                            </select>
                            <button class="btn primary" onclick="app.filterProspects()">Apply Filters</button>
                        </div>
                    </div>
                </div>

                <div class="prospects-table-container">
                    <table class="prospects-table" id="prospects-table">
                        <thead>
                            <tr>
                                <th onclick="app.sortProspects('name')" style="cursor: pointer;">Name ${_sortField === 'name' ? (_sortDirection === 'asc' ? '↑' : '↓') : ''}</th>
                                <th>Agent</th>
                                <th onclick="app.sortProspects('score')" style="cursor: pointer;">Score ${_sortField === 'score' ? (_sortDirection === 'asc' ? '↑' : '↓') : ''}</th>
                                <th>Ming Gua</th>
                                <th>Occupation/Company</th>
                                <th onclick="app.sortProspects('activity')" style="cursor: pointer;">Last Activity ${_sortField === 'activity' ? (_sortDirection === 'asc' ? '↑' : '↓') : ''}</th>
                                <th onclick="app.sortProspects('protection')" style="cursor: pointer;">Protection ${_sortField === 'protection' ? (_sortDirection === 'asc' ? '↑' : '↓') : ''}</th>
                                <th>Actions</th>
                            </tr>

                        </thead>
                        <tbody id="prospects-table-body">
                            <!-- Populated by await renderProspectsTable() -->
                        </tbody>
                    </table>
                </div>
                </div>
                <div id="customers-tab-content" style="display: none;">
                    <!-- Customer view content will be injected here -->
                </div>
            </div>
        `;
        await renderProspectsTable();
    };

    const switchCustomerTab = async (tabName) => {
        const pTab = document.getElementById('prospects-tab-content');
        const cTab = document.getElementById('customers-tab-content');
        const btns = document.querySelectorAll('.tab-btn');

        btns.forEach(b => b.classList.remove('active'));
        if (tabName === 'prospects') {
            pTab.style.display = 'block';
            cTab.style.display = 'none';
            btns[0].classList.add('active');
            await renderProspectsTable();
        } else {
            pTab.style.display = 'none';
            cTab.style.display = 'block';
            btns[1].classList.add('active');
            await showCustomersView(cTab);
        }
    };

    const showCustomersView = async (container) => {
        container.innerHTML = `
            <div class="customers-view">
                <div class="prospects-header">
                    <div>
                        <h1>Customer Database</h1>
                        <p>Manage converted customers and their lifecycle events. Customer records are permanent.</p>
                    </div>
                    <div class="header-actions">
                        <button class="btn primary" onclick="app.openAddCustomerModal()">
                            <i class="fas fa-plus"></i> Add Customer
                        </button>
                    </div>
                </div>

                <div class="warning-banner">
                    <i class="fas fa-exclamation-triangle"></i>
                    <span>⚠️ DELETE IS NOT AVAILABLE - Customer records are permanent and cannot be deleted under any circumstances.</span>
                </div>

                ${(_getUserLevel(_currentUser) <= 4) ? `
                <div id="approval-queue-section" style="margin-bottom:24px;">
                    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:12px;">
                        <h2 style="font-size:18px; font-weight:600; display:flex; align-items:center; gap:8px; margin:0;">
                            <i class="fas fa-clipboard-check" style="color:#d97706;"></i>
                            Manager Approval Queue
                            <span id="approval-queue-count" style="background:#fef3c7; color:#92400e; padding:2px 10px; border-radius:12px; font-size:12px; font-weight:600;">0</span>
                        </h2>
                        <button class="btn secondary" onclick="app.refreshApprovalQueue()" style="font-size:12px; padding:4px 12px;">
                            <i class="fas fa-sync-alt"></i> Refresh
                        </button>
                    </div>
                    <div class="prospects-table-container">
                        <table class="prospects-table">
                            <thead>
                                <tr>
                                    <th>Type</th>
                                    <th>Prospect / Customer</th>
                                    <th>Submitted By</th>
                                    <th>Date</th>
                                    <th>Description</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody id="approval-queue-body">
                            </tbody>
                        </table>
                    </div>
                </div>
                ` : ''}

                <div class="filter-bar" style="flex-direction:column; align-items:stretch; gap:8px;">
                    <div class="search-group">
                        <i class="fas fa-search"></i>
                        <input type="text" id="customer-search" placeholder="Search customers by name, phone, email, or ID" oninput="app.debounceCall('customer-search', app.filterCustomers, 220)">
                    </div>
                    <div>
                        <button type="button" onclick="(function(){var p=document.getElementById('customer-adv-filters');var i=document.getElementById('customer-adv-icon');if(p.style.display==='none'){p.style.display='flex';i.className='fas fa-chevron-up';}else{p.style.display='none';i.className='fas fa-chevron-down';}})()" style="background:none;border:none;cursor:pointer;color:var(--primary);font-size:13px;padding:0;display:flex;align-items:center;gap:6px;">
                            <i id="customer-adv-icon" class="fas fa-chevron-down"></i> Advanced Search
                        </button>
                        <div id="customer-adv-filters" style="display:none; flex-wrap:wrap; gap:8px; margin-top:8px;">
                            <select id="filter-customer-type" onchange="app.filterCustomers()">
                                <option value="">Customer Type: All</option>
                                <option value="Regular">Regular</option>
                                <option value="VIP">VIP</option>
                                <option value="Agent Eligible">Agent Eligible</option>
                            </select>
                            <select id="filter-customer-gua" onchange="app.filterCustomers()">
                                <option value="">Ming Gua: All</option>
                                <option value="MG1">MG1 坎</option>
                                <option value="MG2">MG2 坤</option>
                                <option value="MG3">MG3 震</option>
                                <option value="MG4">MG4 巽</option>
                                <option value="MG5">MG5</option>
                                <option value="MG6">MG6 乾</option>
                                <option value="MG7">MG7 兑</option>
                                <option value="MG8">MG8 艮</option>
                                <option value="MG9">MG9 离</option>
                            </select>
                            <select id="filter-purchase-status" onchange="app.filterCustomers()">
                                <option value="">Purchase Status: All</option>
                                <option value="30d">Purchased Last 30 Days</option>
                                <option value="90d">Purchased Last 90 Days</option>
                                <option value="no90d">No Purchase 90+ Days</option>
                            </select>
                            <select id="filter-customer-deficiency" onchange="app.filterCustomers()">
                                <option value="">Star Deficiency: All</option>
                                <option value="Wealth">Wealth</option>
                                <option value="Career">Career</option>
                                <option value="Relationship">Romance/Relationship</option>
                                <option value="Health">Health</option>
                            </select>
                            <select id="filter-customer-house-audit" onchange="app.filterCustomers()">
                                <option value="">House Audit: All</option>
                                <option value="Pending">Pending</option>
                                <option value="Scheduled">Scheduled</option>
                                <option value="Completed">Completed</option>
                                <option value="None">Not Done</option>
                            </select>
                            <input type="number" id="filter-customer-min-events" min="0" placeholder="Min events attended" onchange="app.filterCustomers()" style="width:160px; padding:6px 10px; border:1px solid var(--border); border-radius:6px; background:var(--surface); color:var(--text);">
                            <button class="btn primary" onclick="app.filterCustomers()">Apply Filters</button>
                        </div>
                    </div>
                </div>

                <div class="prospects-table-container">
                    <table class="prospects-table">
                        <thead>
                            <tr>
                                <th>Name</th>
                                <th>Lifetime Value</th>
                                <th>Customer Since</th>
                                <th>Ming Gua</th>
                                <th>Agent</th>
                                <th>Health</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody id="customers-table-body">
                            <!-- Populated by await renderCustomersTable() -->
                        </tbody>
                    </table>
                </div>
            </div>
        `;
        await renderCustomersTable();
        await renderApprovalQueue();
    };

    // ── Pagination state for customers table ──
    let _customerPage = 0;
    const _customerPageSize = 50;

    const renderCustomersTable = async () => {
        const tbody = document.getElementById('customers-table-body');
        if (!tbody) return;

        // ── Use getAll() with cache (proven reliable) ──
        const customers = await getVisibleCustomers();
        const allUsers = await AppDataStore.getAll('users');
        const userById = new Map(allUsers.map(u => [String(u.id), u]));

        const _custUserLevel = _getUserLevel(_currentUser);
        const canReassignCust = _custUserLevel <= 5;
        const activeAgentsCust = canReassignCust ? allUsers.filter(u => {
            const lvl = _getUserLevel(u);
            return lvl >= 3 && lvl <= 11 && u.status !== 'deleted';
        }) : [];

        const searchQuery = document.getElementById('customer-search')?.value?.trim()?.toLowerCase() || '';
        const typeFilter = document.getElementById('filter-customer-type')?.value || '';
        const guaFilter = document.getElementById('filter-customer-gua')?.value || '';
        const purchaseFilter = document.getElementById('filter-purchase-status')?.value || '';
        const deficiencyFilter = document.getElementById('filter-customer-deficiency')?.value || '';
        const houseAuditFilter = document.getElementById('filter-customer-house-audit')?.value || '';
        const minEventsFilter = parseInt(document.getElementById('filter-customer-min-events')?.value || '0');

        let allEventRegs = [];
        if (minEventsFilter > 0) allEventRegs = await AppDataStore.getAll('event_registrations');

        // ── Apply filters ──
        let filtered = [];
        for (const c of customers) {
            if (searchQuery && !(
                (c.full_name || '').toLowerCase().includes(searchQuery) ||
                (c.nickname && c.nickname.toLowerCase().includes(searchQuery)) ||
                (c.phone && c.phone.includes(searchQuery)) ||
                (c.email && c.email.toLowerCase().includes(searchQuery))
            )) continue;
            if (guaFilter && c.ming_gua !== guaFilter) continue;
            if (typeFilter === 'VIP' && (c.lifetime_value || 0) < 5000) continue;
            if (deficiencyFilter) {
                const needs = c.needs ? (Array.isArray(c.needs) ? c.needs : c.needs.split(',').map(t => t.trim())) : [];
                if (!needs.includes(deficiencyFilter)) continue;
            }
            if (houseAuditFilter) {
                const auditStatus = c.house_audit_status || 'None';
                if (auditStatus !== houseAuditFilter) continue;
            }
            if (minEventsFilter > 0) {
                const attendedCount = allEventRegs.filter(r => r.attendee_id === c.id).length;
                if (attendedCount < minEventsFilter) continue;
            }
            filtered.push(c);
        }

        // ── Client-side pagination ──
        const totalCount = filtered.length;
        const pageStart = _customerPage * _customerPageSize;
        const pageCustomers = filtered.slice(pageStart, pageStart + _customerPageSize);

        let html = '';
        for (const c of pageCustomers) {
            const agent = userById.get(String(c.responsible_agent_id || c.agent_id));
            const agentName = agent ? agent.full_name : '—';

            html += `
                <tr onclick="app.showCustomerDetail(${c.id})">
                    <td data-label="Name"><strong>${c.full_name}</strong></td>
                    <td data-label="Lifetime Value">RM ${(c.lifetime_value || 0).toLocaleString()} <span style="color:var(--success); font-size:12px;"><i class="fas fa-caret-up"></i></span></td>
                    <td data-label="Customer Since">${c.customer_since || '—'}</td>
                    <td data-label="Ming Gua">${c.ming_gua || '—'}</td>
                    <td data-label="Agent" onclick="event.stopPropagation()">${canReassignCust
                        ? `<select class="form-control" style="padding:2px 6px;font-size:12px;min-width:120px;border:1px solid var(--border);border-radius:4px;background:var(--surface);cursor:pointer;" onchange="app.quickReassign(${c.id}, this.value)" title="Reassign agent">${activeAgentsCust.map(a => `<option value="${a.id}" ${String(a.id) === String(c.responsible_agent_id || c.agent_id) ? 'selected' : ''}>${a.full_name || 'Agent'}</option>`).join('')}</select>`
                        : agentName}</td>
                    <td data-label="Health">${renderQuickHealthBadge(c)}</td>
                    <td data-label="Status"><span class="score-badge score-A+">${(c.status || 'active').toUpperCase()}</span></td>
                    <td onclick="event.stopPropagation()">
                        <button class="btn-icon" title="Edit"><i class="fas fa-edit"></i></button>
                        <button class="btn-icon" title="Add Purchase" onclick="app.openAddPurchaseModal(${c.id})"><i class="fas fa-shopping-cart"></i></button>
                        <button class="btn-icon" title="Referral" onclick="event.stopPropagation(); app.openCustomerReferralModal(${c.id})"><i class="fas fa-user-plus"></i></button>
                        <button class="btn-icon" title="Recruit" onclick="app.openRecruitModal(${c.id})"><i class="fas fa-user-tie"></i></button>
                    </td>
                </tr>
            `;
        }
        tbody.innerHTML = html || '<tr><td colspan="8" style="text-align:center; padding:20px;">No customers found</td></tr>';

        // ── Render pagination controls ──
        const totalPages = Math.ceil(totalCount / _customerPageSize);
        let paginationEl = document.getElementById('customers-pagination');
        if (!paginationEl) {
            paginationEl = document.createElement('div');
            paginationEl.id = 'customers-pagination';
            paginationEl.style.cssText = 'display:flex;align-items:center;justify-content:center;gap:8px;padding:16px 0;flex-wrap:wrap;';
            tbody.closest('.prospects-table-container')?.appendChild(paginationEl);
        }
        if (totalPages <= 1) {
            paginationEl.innerHTML = `<span style="color:var(--text-secondary);font-size:13px;">${totalCount} customer${totalCount !== 1 ? 's' : ''}</span>`;
        } else {
            const currentPage = _customerPage + 1;
            const from = pageStart + 1;
            const to = Math.min(pageStart + _customerPageSize, totalCount);
            let pgHtml = `<span style="color:var(--text-secondary);font-size:13px;">Showing ${from}–${to} of ${totalCount}</span>`;
            pgHtml += `<button class="btn secondary btn-sm" ${_customerPage === 0 ? 'disabled' : ''} onclick="app.customerPageNav('first')" title="First page"><i class="fas fa-angle-double-left"></i></button>`;
            pgHtml += `<button class="btn secondary btn-sm" ${_customerPage === 0 ? 'disabled' : ''} onclick="app.customerPageNav('prev')"><i class="fas fa-angle-left"></i> Prev</button>`;
            pgHtml += `<span style="font-weight:600;font-size:14px;">Page ${currentPage} of ${totalPages}</span>`;
            pgHtml += `<button class="btn secondary btn-sm" ${currentPage >= totalPages ? 'disabled' : ''} onclick="app.customerPageNav('next')">Next <i class="fas fa-angle-right"></i></button>`;
            pgHtml += `<button class="btn secondary btn-sm" ${currentPage >= totalPages ? 'disabled' : ''} onclick="app.customerPageNav('last')" title="Last page"><i class="fas fa-angle-double-right"></i></button>`;
            paginationEl.innerHTML = pgHtml;
        }
    };

    const customerPageNav = async (dir) => {
        const paginationText = document.getElementById('customers-pagination')?.textContent || '';
        const totalMatch = paginationText.match(/of (\d+)/);
        const total = totalMatch ? parseInt(totalMatch[1]) : 9999;
        const lastPage = Math.max(0, Math.ceil(total / _customerPageSize) - 1);
        if (dir === 'first') _customerPage = 0;
        else if (dir === 'prev') _customerPage = Math.max(0, _customerPage - 1);
        else if (dir === 'next') _customerPage = Math.min(lastPage, _customerPage + 1);
        else if (dir === 'last') _customerPage = lastPage;
        await renderCustomersTable();
    };

    const filterCustomers = async () => {
        _customerPage = 0; // reset to first page when filters change
        await renderCustomersTable();
    };

    // ========== MANAGER APPROVAL QUEUE ==========

    const renderApprovalQueue = async () => {
        const tbody = document.getElementById('approval-queue-body');
        if (!tbody) return;

        const allEntries = await AppDataStore.getAll('approval_queue');
        // Hide stale info_update entries for prospects that were never converted
        // to customers — those should never have reached the queue (a previous
        // bug created them on every prospect edit). Approval gating only makes
        // sense once the prospect is a customer, so filter them out here too.
        const allProspects = await AppDataStore.getAll('prospects');
        const convertedIds = new Set(
            (allProspects || []).filter(p => p?.status === 'converted').map(p => String(p.id))
        );
        const pending = allEntries
            .filter(e => e.status === 'pending')
            .filter(e => e.approval_type !== 'info_update' || convertedIds.has(String(e.prospect_id)))
            .sort((a, b) => new Date(b.submitted_at) - new Date(a.submitted_at));

        const countEl = document.getElementById('approval-queue-count');
        if (countEl) countEl.textContent = pending.length;

        if (pending.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align:center; padding:24px; color:var(--gray-400);"><i class="fas fa-check-circle" style="margin-right:6px;"></i>No pending approvals</td></tr>';
            return;
        }

        let html = '';
        for (const entry of pending) {
            const agentName = await getAgentName(entry.submitted_by);
            const name = entry.snapshot_after?.full_name || '-';
            const typeConfig = {
                new_customer: { label: 'New Customer', icon: 'fa-user-plus', bg: '#dbeafe', color: '#1e40af' },
                info_update: { label: 'Info Update', icon: 'fa-edit', bg: '#fef3c7', color: '#92400e' },
                new_sale: { label: 'New Sale', icon: 'fa-dollar-sign', bg: '#d1fae5', color: '#065f46' }
            };
            const tc = typeConfig[entry.approval_type] || { label: entry.approval_type, icon: 'fa-question', bg: '#f3f4f6', color: '#374151' };
            const dateStr = entry.submitted_at ? new Date(entry.submitted_at).toLocaleDateString('en-MY', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' }) : '-';

            html += `<tr>
                <td><span style="background:${tc.bg}; color:${tc.color}; padding:3px 10px; border-radius:6px; font-size:12px; font-weight:600; white-space:nowrap;"><i class="fas ${tc.icon}" style="margin-right:4px;"></i>${tc.label}</span></td>
                <td><strong>${name}</strong></td>
                <td>${agentName}</td>
                <td style="font-size:12px; white-space:nowrap;">${dateStr}</td>
                <td style="max-width:220px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; font-size:13px;">${entry.description || '-'}</td>
                <td onclick="event.stopPropagation()">
                    <button class="btn-icon" title="View Details" onclick="event.stopPropagation();app.showApprovalDetail(${entry.id})"><i class="fas fa-eye"></i></button>
                    <button class="btn-icon" title="Approve" style="color:#16a34a;" onclick="event.stopPropagation();app.approveQueueEntry(${entry.id})"><i class="fas fa-check-circle"></i></button>
                    <button class="btn-icon" title="Reject" style="color:#dc2626;" onclick="event.stopPropagation();app.rejectQueueEntry(${entry.id})"><i class="fas fa-times-circle"></i></button>
                </td>
            </tr>`;
        }
        tbody.innerHTML = html;
    };

    const showApprovalDetail = async (entryId) => {
        const entry = await AppDataStore.getById('approval_queue', entryId);
        if (!entry) return UI.toast.error('Approval entry not found');

        const agentName = await getAgentName(entry.submitted_by);
        const snapshot = entry.snapshot_after || {};
        let detailHtml = '';

        if (entry.approval_type === 'new_customer') {
            const cr = snapshot.closing_record;
            const saleAmount = parseFloat(cr?.sale_amount) || 0;
            detailHtml = `
                <div style="background:#dbeafe; border:1px solid #93c5fd; border-radius:8px; padding:12px; font-size:13px; color:#1e40af; margin-bottom:14px;">
                    <i class="fas fa-user-plus" style="margin-right:6px;"></i>
                    New customer conversion requested by <strong>${agentName}</strong>. Approving will create a permanent Customer profile.
                </div>
                <div style="font-size:13px; display:grid; grid-template-columns:1fr 1fr; gap:8px;">
                    <div><span style="color:var(--gray-500);">Name:</span> <strong>${snapshot.full_name || '-'}</strong></div>
                    <div><span style="color:var(--gray-500);">Phone:</span> ${snapshot.phone || '-'}</div>
                    <div><span style="color:var(--gray-500);">IC:</span> ${snapshot.ic_number || '-'}</div>
                    <div><span style="color:var(--gray-500);">DOB:</span> ${snapshot.date_of_birth || '-'}</div>
                    <div><span style="color:var(--gray-500);">Email:</span> ${snapshot.email || '-'}</div>
                    <div><span style="color:var(--gray-500);">Occupation:</span> ${snapshot.occupation || '-'}</div>
                    <div><span style="color:var(--gray-500);">Ming Gua:</span> ${snapshot.ming_gua || '-'}</div>
                    <div><span style="color:var(--gray-500);">Referrer:</span> ${snapshot.referred_by || '-'}</div>
                </div>
                ${cr ? `
                    <div style="border-top:1px solid var(--gray-200); padding-top:12px; margin-top:12px;">
                        <div style="font-weight:600; margin-bottom:8px; font-size:13px;">Sales Record</div>
                        <div style="font-size:13px; display:grid; grid-template-columns:1fr 1fr; gap:8px;">
                            <div><span style="color:var(--gray-500);">Product:</span> ${cr.product || '-'}</div>
                            <div><span style="color:var(--gray-500);">Amount:</span> <strong style="color:#166534;">RM ${saleAmount.toLocaleString()}</strong></div>
                            <div><span style="color:var(--gray-500);">Invoice:</span> ${cr.invoice_number || '-'}</div>
                            <div><span style="color:var(--gray-500);">Date:</span> ${cr.closing_date || '-'}</div>
                        </div>
                    </div>
                ` : ''}`;
        } else if (entry.approval_type === 'info_update') {
            const before = entry.snapshot_before || {};
            const after = entry.snapshot_after || {};
            const fields = ['full_name','nickname','phone','email','ic_number','date_of_birth','lunar_birth','ming_gua','occupation','company_name','income_range','address','city','state','postal_code','title','gender','nationality','referred_by','referral_relationship'];
            const changedFields = fields.filter(f => before[f] !== undefined && after[f] !== undefined && String(before[f] || '') !== String(after[f] || ''));

            detailHtml = `
                <div style="background:#fef3c7; border:1px solid #fcd34d; border-radius:8px; padding:12px; font-size:13px; color:#92400e; margin-bottom:14px;">
                    <i class="fas fa-edit" style="margin-right:6px;"></i>
                    Information updated by <strong>${agentName}</strong>. Review changes below.
                </div>
                ${changedFields.length > 0 ? `
                    <table style="width:100%; border-collapse:collapse; font-size:13px;">
                        <thead><tr>
                            <th style="text-align:left; padding:6px 8px; border-bottom:2px solid var(--gray-200); color:var(--gray-500);">Field</th>
                            <th style="text-align:left; padding:6px 8px; border-bottom:2px solid var(--gray-200); color:#dc2626;">Before</th>
                            <th style="text-align:left; padding:6px 8px; border-bottom:2px solid var(--gray-200); color:#16a34a;">After</th>
                        </tr></thead>
                        <tbody>${changedFields.map(f => `<tr>
                            <td style="padding:6px 8px; border-bottom:1px solid var(--gray-100); font-weight:500;">${f.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())}</td>
                            <td style="padding:6px 8px; border-bottom:1px solid var(--gray-100); color:#dc2626; text-decoration:line-through;">${before[f] || '<em>empty</em>'}</td>
                            <td style="padding:6px 8px; border-bottom:1px solid var(--gray-100); color:#16a34a; font-weight:600;">${after[f] || '<em>empty</em>'}</td>
                        </tr>`).join('')}</tbody>
                    </table>
                ` : '<div style="color:var(--gray-400); font-size:13px; font-style:italic; padding:12px;">No field differences detected.</div>'}`;
        } else if (entry.approval_type === 'new_sale') {
            const cr = entry.snapshot_after || {};
            const saleAmount = parseFloat(cr.sale_amount) || 0;
            detailHtml = `
                <div style="background:#d1fae5; border:1px solid #6ee7b7; border-radius:8px; padding:12px; font-size:13px; color:#065f46; margin-bottom:14px;">
                    <i class="fas fa-dollar-sign" style="margin-right:6px;"></i>
                    New sale submitted by <strong>${agentName}</strong>. Review closing record below.
                </div>
                <div style="font-size:13px; display:grid; grid-template-columns:1fr 1fr; gap:8px;">
                    <div><span style="color:var(--gray-500);">Prospect:</span> <strong>${cr.full_name || snapshot.prospect_name || '-'}</strong></div>
                    <div><span style="color:var(--gray-500);">Product:</span> ${cr.product || '-'}</div>
                    <div><span style="color:var(--gray-500);">Sale Amount:</span> <strong style="color:#166534;">RM ${saleAmount.toLocaleString()}</strong></div>
                    <div><span style="color:var(--gray-500);">Payment:</span> ${cr.payment_method || '-'}</div>
                    <div><span style="color:var(--gray-500);">Invoice:</span> ${cr.invoice_number || '-'}</div>
                    <div><span style="color:var(--gray-500);">Closing Date:</span> ${cr.closing_date || '-'}</div>
                    ${cr.sales_idea ? `<div style="grid-column:1/-1;"><span style="color:var(--gray-500);">Sales Idea:</span> ${cr.sales_idea}</div>` : ''}
                </div>`;
        }

        UI.showModal('Approval Details', `
            <div style="display:flex; flex-direction:column; gap:14px;">
                ${detailHtml}
                <div style="font-size:12px; color:var(--gray-400); border-top:1px solid var(--gray-100); padding-top:8px;">
                    Submitted: ${new Date(entry.submitted_at).toLocaleString('en-MY')} | By: ${agentName}
                </div>
            </div>
        `, [
            { label: '<i class="fas fa-times-circle"></i> Reject', type: 'secondary', action: `(async () => { UI.hideModal(); await app.rejectQueueEntry(${entryId}); })()` },
            { label: '<i class="fas fa-check-circle"></i> Approve', type: 'primary', action: `(async () => { await app.approveQueueEntry(${entryId}); })()` }
        ]);
    };

    const approveQueueEntry = async (entryId) => {
        const entry = await AppDataStore.getById('approval_queue', entryId);
        if (!entry || entry.status !== 'pending') return UI.toast.error('Entry not found or already processed.');

        const now = new Date().toISOString();

        if (entry.approval_type === 'new_customer') {
            await approveProspectConversion(entry.prospect_id);
        } else if (entry.approval_type === 'info_update') {
            const prospect = await AppDataStore.getById('prospects', entry.prospect_id);
            if (prospect?.status === 'converted') {
                const customers = await AppDataStore.getAll('customers');
                const customer = customers.find(c => c.converted_from_prospect_id == entry.prospect_id);
                if (customer) {
                    const syncable = ['title','full_name','nickname','gender','nationality','phone','email','ic_number','date_of_birth','lunar_birth','ming_gua','occupation','company_name','income_range','address','city','state','postal_code','referred_by','referred_by_id','referred_by_type','referral_relationship'];
                    const syncFields = {};
                    for (const field of syncable) {
                        if (entry.snapshot_after[field] !== undefined) {
                            syncFields[field] = entry.snapshot_after[field];
                        }
                    }
                    if (Object.keys(syncFields).length > 0) {
                        await AppDataStore.update('customers', customer.id, syncFields);
                    }
                }
            }
        } else if (entry.approval_type === 'new_sale') {
            const prospect = await AppDataStore.getById('prospects', entry.prospect_id);
            if (prospect?.status === 'converted') {
                const customers = await AppDataStore.getAll('customers');
                const customer = customers.find(c => c.converted_from_prospect_id == entry.prospect_id);
                if (customer) {
                    const cr = entry.snapshot_after;
                    const amt = parseFloat(cr.sale_amount) || 0;
                    await AppDataStore.create('purchases', {
                        id: Date.now(),
                        customer_id: customer.id,
                        date: cr.closing_date || now.split('T')[0],
                        invoice: cr.invoice_number || '',
                        item: cr.product || '',
                        amount: amt,
                        status: 'COMPLETED',
                        payment_method: cr.payment_method || 'Cash'
                    });
                    await AppDataStore.update('customers', customer.id, {
                        lifetime_value: (customer.lifetime_value || 0) + amt
                    });
                }
            }
            if (prospect?.closing_record?.status === 'submitted') {
                const approvedCr = { ...prospect.closing_record, status: 'approved', approved_at: now };
                const existingHistory = Array.isArray(prospect.closing_records_history) ? prospect.closing_records_history : [];
                await AppDataStore.update('prospects', entry.prospect_id, {
                    closing_record: null,
                    closing_records_history: [...existingHistory, approvedCr]
                });
            }
        }

        await AppDataStore.update('approval_queue', entryId, {
            status: 'approved',
            reviewed_by: _currentUser?.id,
            reviewed_at: now
        });

        UI.hideModal();
        UI.toast.success('Approved successfully!');
        await renderApprovalQueue();
        await renderCustomersTable();
    };

    const rejectQueueEntry = async (entryId) => {
        const entry = await AppDataStore.getById('approval_queue', entryId);
        if (!entry || entry.status !== 'pending') return UI.toast.error('Entry not found or already processed.');

        UI.showModal('Reject Approval', `
            <div style="display:flex; flex-direction:column; gap:12px;">
                <div style="background:#fef2f2; border:1px solid #fecaca; border-radius:8px; padding:12px; font-size:13px; color:#991b1b;">
                    <i class="fas fa-exclamation-circle" style="margin-right:6px;"></i>
                    You are rejecting: <strong>${entry.description || 'this entry'}</strong>
                </div>
                <div class="form-group">
                    <label>Reason for rejection</label>
                    <textarea id="reject-reason" class="form-control" rows="3" placeholder="Explain why this is being rejected..." style="width:100%;"></textarea>
                </div>
            </div>
        `, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: '<i class="fas fa-times"></i> Confirm Reject', type: 'primary', action: `(async () => { await app.confirmRejectQueueEntry(${entryId}); })()` }
        ]);
    };

    const confirmRejectQueueEntry = async (entryId) => {
        const reason = document.getElementById('reject-reason')?.value?.trim() || '';
        const entry = await AppDataStore.getById('approval_queue', entryId);
        if (!entry) return;

        if (entry.approval_type === 'info_update' && entry.snapshot_before) {
            const revertFields = {};
            for (const key of Object.keys(entry.snapshot_after)) {
                if (entry.snapshot_before[key] !== undefined) {
                    revertFields[key] = entry.snapshot_before[key];
                }
            }
            if (Object.keys(revertFields).length > 0) {
                await AppDataStore.update('prospects', entry.prospect_id, revertFields);
            }
        }

        if (entry.approval_type === 'new_customer') {
            await AppDataStore.update('prospects', entry.prospect_id, {
                conversion_status: 'rejected',
                conversion_rejected_at: new Date().toISOString(),
                conversion_rejected_by: _currentUser?.id
            });
        }

        if (entry.approval_type === 'new_sale') {
            const prospect = await AppDataStore.getById('prospects', entry.prospect_id);
            if (prospect?.closing_record?.status === 'submitted') {
                await AppDataStore.update('prospects', entry.prospect_id, {
                    closing_record: { ...prospect.closing_record, status: 'draft', rejected_at: new Date().toISOString(), reject_reason: reason }
                });
            }
        }

        await AppDataStore.update('approval_queue', entryId, {
            status: 'rejected',
            reviewed_by: _currentUser?.id,
            reviewed_at: new Date().toISOString(),
            reject_reason: reason
        });

        UI.hideModal();
        UI.toast.info('Approval rejected.');
        await renderApprovalQueue();
    };

    const _downloadSheet = (cols, rows, sheetName, filename, format) => {
        if (format === 'xlsx') {
            const ws = XLSX.utils.aoa_to_sheet([cols, ...rows]);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, sheetName);
            XLSX.writeFile(wb, `${filename}.xlsx`);
        } else {
            const csvRows = [cols, ...rows].map(r => r.map(v => `"${String(v).replace(/"/g, '""')}"`).join(','));
            const blob = new Blob([csvRows.join('\n')], { type: 'text/csv' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a'); a.href = url; a.download = `${filename}.csv`;
            document.body.appendChild(a); a.click(); document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }
    };

    const exportData = async (type, format) => {
        const today = new Date().toISOString().split('T')[0];
        const filename = `${type}_export_${today}`;

        if (type === 'prospects') {
            const data = await getVisibleProspects();
            if (!data.length) { UI.toast.error('No prospects to export'); return; }
            const cols = ['Full Name','Phone','Email','IC Number','Date of Birth','Occupation','Company','Income Range','Address','City','State','Postal Code','Ming Gua','Pipeline Stage','Deal Value (RM)','Score','Source','Status','Created At'];
            const rows = data.map(p => [p.full_name||'', p.phone||'', p.email||'', p.ic_number||'', p.date_of_birth||'', p.occupation||'', p.company_name||'', p.income_range||'', p.address||'', p.city||'', p.state||'', p.postal_code||'', p.ming_gua||'', p.pipeline_stage||'', p.deal_value||'', p.score||'', p.source||'', p.status||'', p.created_at?p.created_at.split('T')[0]:'']);
            _downloadSheet(cols, rows, 'Prospects', filename, format);
            UI.toast.success(`Exported ${data.length} prospects`);

        } else if (type === 'prospects_activities') {
            const prospects = await getVisibleProspects();
            if (!prospects.length) { UI.toast.error('No prospects to export'); return; }
            const activities = await getVisibleActivities();
            const pCols = ['Full Name','Phone','Email','IC Number','Date of Birth','Occupation','Company','Income Range','Address','City','State','Postal Code','Ming Gua','Pipeline Stage','Deal Value (RM)','Score','Source','Status','Created At'];
            const pRows = prospects.map(p => [p.full_name||'', p.phone||'', p.email||'', p.ic_number||'', p.date_of_birth||'', p.occupation||'', p.company_name||'', p.income_range||'', p.address||'', p.city||'', p.state||'', p.postal_code||'', p.ming_gua||'', p.pipeline_stage||'', p.deal_value||'', p.score||'', p.source||'', p.status||'', p.created_at?p.created_at.split('T')[0]:'']);
            const prospectMap = Object.fromEntries(prospects.map(p => [p.id, p.full_name]));
            const aCols = ['Prospect Name','Date','Type','Title','Start Time','End Time','Status','Notes','Lead Agent ID'];
            const aRows = activities.map(a => [prospectMap[a.prospect_id]||'', a.activity_date||'', a.activity_type||'', a.activity_title||'', a.start_time||'', a.end_time||'', a.status||'', a.notes||'', a.lead_agent_id||'']);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet([pCols, ...pRows]), 'Prospects');
            XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet([aCols, ...aRows]), 'Activities');
            XLSX.writeFile(wb, `${filename}.xlsx`);
            UI.toast.success(`Exported ${prospects.length} prospects and ${activities.length} activities`);

        } else if (type === 'customers') {
            const data = await getVisibleCustomers();
            if (!data.length) { UI.toast.error('No customers to export'); return; }
            const cols = ['Full Name','Phone','Email','IC Number','Date of Birth','Address','City','State','Lifetime Value (RM)','Status','Customer Since','Created At'];
            const rows = data.map(c => [c.full_name||'', c.phone||'', c.email||'', c.ic_number||'', c.date_of_birth||'', c.address||'', c.city||'', c.state||'', c.lifetime_value||'', c.status||'', c.customer_since||'', c.created_at?c.created_at.split('T')[0]:'']);
            _downloadSheet(cols, rows, 'Customers', filename, format);
            UI.toast.success(`Exported ${data.length} customers`);

        } else if (type === 'agents') {
            const allUsers = await AppDataStore.getAll('users');
            const data = allUsers.filter(u => u.full_name);
            if (!data.length) { UI.toast.error('No agents to export'); return; }
            const cols = ['Full Name','Role','Agent Code','Phone','Email','IC Number','Team','Commission Rate (%)','License Start','License Expiry','Status','Join Date'];
            const rows = data.map(a => [a.full_name||'', a.role||'', a.agent_code||'', a.phone||'', a.email||'', a.ic_number||'', a.team||'', a.commission_rate||'', a.license_start||'', a.license_expiry||'', a.status||'', a.join_date||'']);
            _downloadSheet(cols, rows, 'Agents', filename, format);
            UI.toast.success(`Exported ${data.length} consultants/agents`);

        } else if (['products','events','promotions'].includes(type)) {
            _currentMarketingListTab = type;
            await exportMarketingList(format);
        }
    };

    const renderProspectsTable = async () => {
        const tbody = document.getElementById('prospects-table-body');
        if (!tbody) return;

        // ── Use getAll() with cache (5-min TTL, light-select, proven reliable) ──
        // Then filter + paginate client-side. First load downloads ~100KB (no blobs),
        // subsequent calls hit cache instantly.
        const [allProspects, allActivities, allUsers] = await Promise.all([
            AppDataStore.getAll('prospects'),
            AppDataStore.getAll('activities'),
            AppDataStore.getAll('users'),
        ]);

        // ── Scope by role hierarchy ──
        let prospects;
        if (isSystemAdmin(_currentUser)) {
            prospects = allProspects;
        } else {
            const visibleIds = await getVisibleUserIds(_currentUser);
            if (visibleIds === 'all') {
                prospects = allProspects;
            } else {
                prospects = allProspects.filter(p => visibleIds.includes(p.responsible_agent_id));
            }
        }

        // ── Read UI filter values ──
        const searchQuery = document.getElementById('prospect-search')?.value?.trim()?.toLowerCase() || '';
        const scoreFilter = document.getElementById('filter-score')?.value || '';
        const guaFilter = document.getElementById('filter-gua')?.value || '';
        const statusFilter = document.getElementById('filter-status')?.value || '';
        const agentFilter = document.getElementById('filter-agent')?.value || '';

        // ── Build activity index (O(1) lookups) ──
        const latestActivityByProspect = new Map();
        for (const a of allActivities) {
            if (a.prospect_id == null) continue;
            const key = String(a.prospect_id);
            const current = latestActivityByProspect.get(key);
            if (!current) { latestActivityByProspect.set(key, a); continue; }
            const curKey = (current.activity_date || '') + '|' + (current.id || 0);
            const newKey = (a.activity_date || '') + '|' + (a.id || 0);
            if (newKey > curKey) latestActivityByProspect.set(key, a);
        }
        const userById = new Map(allUsers.map(u => [String(u.id), u]));

        // ── Populate agent filter dropdown (agents visible to current user) ──
        const agentFilterEl = document.getElementById('filter-agent');
        if (agentFilterEl) {
            const currentAgentVal = agentFilterEl.value;
            const visibleAgents = allUsers.filter(u => {
                const lvl = _getUserLevel(u);
                return lvl >= 3 && lvl <= 11 && u.status !== 'deleted';
            }).sort((a, b) => (a.full_name || '').localeCompare(b.full_name || ''));
            agentFilterEl.innerHTML = '<option value="">All Agents</option>' +
                visibleAgents.map(a => `<option value="${a.id}"${String(a.id) === currentAgentVal ? ' selected' : ''}>${a.full_name || 'Agent'}</option>`).join('');
        }

        const _userLvlMatch = _currentUser?.role?.match(/Level\s+(\d+)/i);
        const _userLevel = _userLvlMatch ? parseInt(_userLvlMatch[1]) : 99;
        const canDelete = _userLevel <= 5;
        const canReassign = _userLevel <= 5;
        const activeAgents = canReassign ? allUsers.filter(u => {
            const lvl = _getUserLevel(u);
            return lvl >= 3 && lvl <= 11 && u.status !== 'deleted';
        }) : [];

        // ── Apply sorting ──
        prospects.sort((a, b) => {
            let valA, valB;
            if (_sortField === 'name') {
                valA = a.full_name || ''; valB = b.full_name || '';
                return _sortDirection === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
            } else if (_sortField === 'score') {
                valA = a.score || 0; valB = b.score || 0;
                return _sortDirection === 'asc' ? valA - valB : valB - valA;
            } else if (_sortField === 'activity') {
                const lastA = latestActivityByProspect.get(String(a.id));
                const lastB = latestActivityByProspect.get(String(b.id));
                valA = lastA ? lastA.activity_date : '0000-00-00';
                valB = lastB ? lastB.activity_date : '0000-00-00';
                return _sortDirection === 'asc' ? valA.localeCompare(valB) : valB.localeCompare(valA);
            } else if (_sortField === 'protection') {
                valA = calculateDaysLeft(a.protection_deadline);
                valB = calculateDaysLeft(b.protection_deadline);
                return _sortDirection === 'asc' ? valA - valB : valB - valA;
            }
            return 0;
        });

        // ── Apply filters, then paginate ──
        let filtered = [];
        for (const p of prospects) {
            if (searchQuery && !(
                (p.full_name || '').toLowerCase().includes(searchQuery) ||
                (p.nickname && p.nickname.toLowerCase().includes(searchQuery)) ||
                (p.phone && p.phone.includes(searchQuery)) ||
                (p.email && p.email.toLowerCase().includes(searchQuery)) ||
                (p.id && p.id.toString().includes(searchQuery))
            )) continue;

            const grade = getScoreGrade(p.score);
            if (scoreFilter && scoreFilter !== grade) continue;
            if (guaFilter && p.ming_gua !== guaFilter) continue;
            if (agentFilter && String(p.responsible_agent_id) !== agentFilter) continue;

            const daysLeft = calculateProtectionDays(p);
            const protectionStatus = getProtectionStatus(daysLeft);
            if (statusFilter) {
                if (statusFilter === 'active' && protectionStatus !== 'normal') continue;
                if (statusFilter === 'attention' && protectionStatus !== 'warning') continue;
                if (statusFilter === 'reassign' && protectionStatus !== 'normal') continue;
                if (statusFilter === 'critical' && protectionStatus !== 'critical') continue;
            }
            filtered.push(p);
        }

        // ── Client-side pagination ──
        const totalCount = filtered.length;
        const pageStart = _prospectPage * _prospectPageSize;
        const pageProspects = filtered.slice(pageStart, pageStart + _prospectPageSize);

        let html = '';
        for (const p of pageProspects) {
            const grade = getScoreGrade(p.score);
            const lastActivity = latestActivityByProspect.get(String(p.id));
            const lastActivityText = lastActivity
                ? `${lastActivity.activity_date} ${lastActivity.activity_type}`
                : 'No activity';
            const daysLeft = calculateProtectionDays(p);
            const protectionStatus = getProtectionStatus(daysLeft);
            const agent = userById.get(String(p.responsible_agent_id));
            const agentName = agent ? agent.full_name : '—';

            html += `
                <tr onclick="app.showProspectDetail(${p.id})">
                    <td data-label="Name"><strong>${p.full_name || '(No Name)'}</strong></td>
                    <td data-label="Agent" onclick="event.stopPropagation()">${canReassign
                        ? `<select class="form-control" style="padding:2px 6px;font-size:12px;min-width:120px;border:1px solid var(--border);border-radius:4px;background:var(--surface);cursor:pointer;" onchange="app.quickReassign(${p.id}, this.value)" title="Reassign agent">${!p.responsible_agent_id ? '<option value="" selected>— Unassigned —</option>' : ''}${activeAgents.map(a => `<option value="${a.id}" ${String(a.id) === String(p.responsible_agent_id) ? 'selected' : ''}>${a.full_name || 'Agent'}</option>`).join('')}</select>`
                        : agentName}</td>
                    <td data-label="Score">
                        <span class="score-badge score-${grade.replace('+', '-plus')}">${p.score || 0} (${grade})</span>
                    </td>
                    <td data-label="Ming Gua">${p.ming_gua || 'MG4'}</td>
                    <td data-label="Occupation">${p.occupation || ''}${p.company_name ? ' · ' + p.company_name : ''}</td>
                    <td data-label="Last Activity">${lastActivityText}</td>
                    <td data-label="Protection">
                        <div>${daysLeft} days left</div>
                        <div class="protection-bar">
                            <div class="protection-fill ${protectionStatus}" style="width: ${Math.min(100, (daysLeft / 30) * 100)}%"></div>
                        </div>
                    </td>
                    <td onclick="event.stopPropagation()">
                        <button class="btn-icon" title="Edit" onclick="app.openProspectModal(${p.id})"><i class="fas fa-edit"></i></button>
                        <button class="btn-icon" title="Add Activity" onclick="app.openActivityModal('', ${p.id})"><i class="fas fa-calendar-plus"></i></button>
                        ${p.conversion_status === 'pending_approval' ? `
                            <span title="Conversion pending manager approval" style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;background:#fef3c7;border-radius:6px;cursor:default;"><i class="fas fa-user-clock" style="color:#d97706;font-size:12px;"></i></span>
                            ${(isSystemAdmin(_currentUser) || isMarketingManager(_currentUser)) ? `<button class="btn-icon" title="Review & Approve Conversion" style="color:#d97706;" onclick="event.stopPropagation();app.showConversionApprovalModal(${p.id})"><i class="fas fa-check-circle"></i></button>` : ''}
                        ` : (p.status !== 'converted' ? `
                            <button class="btn-icon" title="Convert to Customer" onclick="app.convertToCustomer(${p.id})"><i class="fas fa-user-check"></i></button>
                        ` : '')}
                        ${canDelete ? `<button class="btn-icon" title="Delete" style="color:var(--red-500);" onclick="app.deleteProspect(${p.id})"><i class="fas fa-trash"></i></button>` : ''}
                    </td>
                </tr>
            `;
        }

        if (pageProspects.length === 0) {
            html = '<tr><td colspan="8" style="text-align:center; padding:40px;">No prospects found. Click "Add Prospect" to create one.</td></tr>';
        }

        tbody.innerHTML = html;

        // ── Render pagination controls ──
        const totalPages = Math.ceil(totalCount / _prospectPageSize);
        let paginationEl = document.getElementById('prospects-pagination');
        if (!paginationEl) {
            paginationEl = document.createElement('div');
            paginationEl.id = 'prospects-pagination';
            paginationEl.style.cssText = 'display:flex;align-items:center;justify-content:center;gap:8px;padding:16px 0;flex-wrap:wrap;';
            tbody.closest('.prospects-table-container')?.appendChild(paginationEl);
        }
        if (totalPages <= 1) {
            paginationEl.innerHTML = `<span style="color:var(--text-secondary);font-size:13px;">${totalCount} prospect${totalCount !== 1 ? 's' : ''}</span>`;
        } else {
            const currentPage = _prospectPage + 1;
            const from = pageStart + 1;
            const to = Math.min(pageStart + _prospectPageSize, totalCount);
            let pgHtml = `<span style="color:var(--text-secondary);font-size:13px;">Showing ${from}–${to} of ${totalCount}</span>`;
            pgHtml += `<button class="btn secondary btn-sm" ${_prospectPage === 0 ? 'disabled' : ''} onclick="app.prospectPageNav('first')" title="First page"><i class="fas fa-angle-double-left"></i></button>`;
            pgHtml += `<button class="btn secondary btn-sm" ${_prospectPage === 0 ? 'disabled' : ''} onclick="app.prospectPageNav('prev')"><i class="fas fa-angle-left"></i> Prev</button>`;
            pgHtml += `<span style="font-weight:600;font-size:14px;">Page ${currentPage} of ${totalPages}</span>`;
            pgHtml += `<button class="btn secondary btn-sm" ${currentPage >= totalPages ? 'disabled' : ''} onclick="app.prospectPageNav('next')">Next <i class="fas fa-angle-right"></i></button>`;
            pgHtml += `<button class="btn secondary btn-sm" ${currentPage >= totalPages ? 'disabled' : ''} onclick="app.prospectPageNav('last')" title="Last page"><i class="fas fa-angle-double-right"></i></button>`;
            paginationEl.innerHTML = pgHtml;
        }
    };

    const prospectPageNav = async (dir) => {
        const visibleIds = await getVisibleUserIds(_currentUser);
        // Estimate total to compute last page — use cached count from last render
        const paginationText = document.getElementById('prospects-pagination')?.textContent || '';
        const totalMatch = paginationText.match(/of (\d+)/);
        const total = totalMatch ? parseInt(totalMatch[1]) : 9999;
        const lastPage = Math.max(0, Math.ceil(total / _prospectPageSize) - 1);
        if (dir === 'first') _prospectPage = 0;
        else if (dir === 'prev') _prospectPage = Math.max(0, _prospectPage - 1);
        else if (dir === 'next') _prospectPage = Math.min(lastPage, _prospectPage + 1);
        else if (dir === 'last') _prospectPage = lastPage;
        await renderProspectsTable();
    };

    const deleteProspect = async (id) => {
        // SECURITY TODO: the `canDelete` check above is client-side only and can
        // be bypassed via DevTools (any agent could call `app.deleteProspect(id)`
        // directly). The real fix is a Supabase RLS policy on `prospects` that
        // restricts DELETE to level ≤ 5 users, e.g.
        //   CREATE POLICY "prospects_delete_lead" ON prospects FOR DELETE
        //     USING (auth.jwt() ->> 'role' IN ('super_admin','marketing_manager','manager','team_leader'));
        // Until RLS is in place, treat this as UI-only gating.
        const userLvlMatch = _currentUser?.role?.match(/Level\s+(\d+)/i);
        const userLevel = userLvlMatch ? parseInt(userLvlMatch[1]) : 99;
        if (userLevel > 5) {
            UI.toast.error('You do not have permission to delete prospects.');
            return;
        }
        UI.showModal('Delete Prospect', '<p>This will permanently delete this prospect and all linked activities, notes, and names. This cannot be undone. Continue?</p>', [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: 'Delete', type: 'primary', action: `(async () => { await app.confirmDeleteProspect(${id}); })()` }
        ]);
    };
    const confirmDeleteProspect = async (id) => {
        // Re-check the role here too — the modal action runs through a global
        // callback and could theoretically be invoked directly.
        const userLvlMatch = _currentUser?.role?.match(/Level\s+(\d+)/i);
        const userLevel = userLvlMatch ? parseInt(userLvlMatch[1]) : 99;
        if (userLevel > 5) {
            UI.hideModal();
            UI.toast.error('You do not have permission to delete prospects.');
            return;
        }
        UI.hideModal();
        try {
            const [acts, allNotes, names] = await Promise.all([
                AppDataStore.query('activities', { prospect_id: id }).catch(() => []),
                AppDataStore.getAll('notes').catch(() => []),
                AppDataStore.query('names', { prospect_id: id }).catch(() => [])
            ]);
            const notes = allNotes.filter(n =>
                String(n.prospect_id) === String(id) ||
                (n.entity_type === 'prospect' && String(n.entity_id) === String(id))
            );
            // Bulk-delete related records in parallel (was sequential — O(N) round trips)
            await Promise.all([
                acts.length ? AppDataStore.deleteMany('activities', acts.map(a => a.id)) : Promise.resolve(),
                notes.length ? AppDataStore.deleteMany('notes', notes.map(n => n.id)) : Promise.resolve(),
                names.length ? AppDataStore.deleteMany('names', names.map(n => n.id)) : Promise.resolve(),
            ]);
            await AppDataStore.delete('prospects', id);
            UI.toast.success('Prospect deleted.');
            await app.renderProspectsTable();
        } catch (err) {
            UI.toast.error('Failed to delete: ' + (err.message || 'Unknown error'));
        }
    };

    const getScoreGrade = (score) => {
        if (!score) return 'D';
        if (score >= 800) return 'A+';
        if (score >= 600) return 'A';
        if (score >= 400) return 'B';
        if (score >= 200) return 'C';
        return 'D';
    };

    // Manual prospect grade picker. Agents set A–G manually from the prospect
    // detail header badge. Stored in prospects.manual_grade (nullable TEXT).
    const openProspectGradePicker = async (prospectId) => {
        const prospect = await AppDataStore.getById('prospects', prospectId);
        if (!prospect) { UI.toast.error('Prospect not found'); return; }
        const currentUser = _currentUser || await Auth.getCurrentUser();
        const isAdmin = isSystemAdmin(currentUser) || isMarketingManager(currentUser) || currentUser.role?.includes('Level 3') || currentUser.role?.includes('Level 7') || currentUser.role === 'team_leader';
        const isOwner = prospect.responsible_agent_id == currentUser.id;
        if (!isAdmin && !isOwner) {
            UI.toast.error('You cannot set the grade for this prospect.');
            return;
        }
        const current = prospect.manual_grade || '';
        const grades = ['A', 'B', 'C', 'D', 'E', 'F', 'G'];
        const btn = (g) => {
            const active = g === current;
            return `<button type="button" onclick="(async () => { await app.setProspectGrade(${prospectId}, '${g}'); })()" style="padding:14px;font-weight:700;font-size:18px;border-radius:10px;border:2px solid ${active ? 'var(--primary)' : 'var(--gray-300)'};background:${active ? 'var(--primary)' : '#fff'};color:${active ? '#fff' : 'var(--gray-800)'};cursor:pointer;transition:all .15s;" onmouseover="if(!${active}){this.style.background='var(--gray-100)';this.style.borderColor='var(--gray-400)';}" onmouseout="if(!${active}){this.style.background='#fff';this.style.borderColor='var(--gray-300)';}">${g}</button>`;
        };
        const content = `
            <div style="padding:4px 0;">
                <p style="margin:0 0 14px;color:var(--gray-600);font-size:14px;">Select a grade for <strong>${prospect.full_name || 'this prospect'}</strong>.</p>
                <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;">
                    ${grades.map(btn).join('')}
                    <button type="button" onclick="(async () => { await app.setProspectGrade(${prospectId}, null); })()" style="padding:14px;font-weight:600;font-size:14px;border-radius:10px;border:2px solid var(--gray-300);background:#fff;color:var(--gray-500);cursor:pointer;" title="Clear grade">None</button>
                </div>
            </div>
        `;
        UI.showModal('Set Prospect Grade', content, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' }
        ]);
    };

    const setProspectGrade = async (prospectId, grade) => {
        try {
            await AppDataStore.update('prospects', prospectId, { manual_grade: grade });
            UI.toast.success(grade ? `Grade set to ${grade}` : 'Grade cleared');
            UI.hideModal();
            await showProspectDetail(prospectId);
        } catch (err) {
            UI.toast.error('Failed to update grade: ' + (err.message || 'Unknown error'));
        }
    };

    const calculateProtectionDays = (prospect) => {
        if (!prospect.protection_deadline) return 30;
        const deadline = new Date(prospect.protection_deadline);
        const today = new Date();
        const diffTime = deadline - today;
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        return diffDays > 0 ? diffDays : 0;
    };

    const getProtectionStatus = (days) => {
        if (days > 7) return 'normal';
        if (days > 0) return 'warning';
        return 'critical';
    };

    const openProspectModal = async (prospectId = null) => {
        if (prospectId) {
            const prospect = await AppDataStore.getById('prospects', prospectId);
            const currentUser = _currentUser || await Auth.getCurrentUser();
            const isAdmin = isSystemAdmin(currentUser) || isMarketingManager(currentUser) || currentUser.role?.includes('Level 3') || currentUser.role?.includes('Level 7') || currentUser.role === 'team_leader';
            const isOwner = prospect.responsible_agent_id == currentUser.id;
            if (!isAdmin && !isOwner) {
                UI.toast.error('You cannot edit this prospect.');
                return;
            }
        }
        const prospect = prospectId ? await AppDataStore.getById('prospects', prospectId) : null;
        _selectedProspectReferrer = prospect?.referred_by ? { name: prospect.referred_by, id: prospect.referred_by_id || null, type: prospect.referred_by_type || null } : null;
        const allUsers = await AppDataStore.getAll('users');
        const isEdit = !!prospect;

        const content = `
            <div class="prospect-form">
                <input type="hidden" id="edit-prospect-id" value="${prospectId || ''}">
                <div class="form-section">
                    <h4>Basic Information</h4>
                    ${buildBasicInfoBlock('prospect', prospect)}
                </div>
            </div>
        `;

        UI.showModal(isEdit ? 'Edit Prospect' : 'Add New Prospect', content, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: isEdit ? 'Update Prospect' : 'Create Prospect', type: 'primary', action: '(async () => { await app.saveProspect(); })()' }
        ]);

        // Pre-populate children rows after modal mounts
        setTimeout(() => prefillProspectChildren(prospect?.children), 0);
    };


    const showFieldError = (fieldId, message) => {
        const field = document.getElementById(fieldId);
        if (field) {
            field.classList.add('error');
            const errorDiv = document.createElement('div');
            errorDiv.className = 'validation-error';
            errorDiv.textContent = message;
            field.parentNode.appendChild(errorDiv);
        }
    };

    const saveProspect = async () => {
        const editId = document.getElementById('edit-prospect-id')?.value;
        const name = document.getElementById('prospect-name')?.value?.trim();
        const phone = document.getElementById('prospect-phone')?.value?.trim();
        const email = document.getElementById('prospect-email')?.value?.trim();

        // Clear previous validation errors
        document.querySelectorAll('.validation-error').forEach(el => el.remove());
        document.querySelectorAll('.form-control.error').forEach(el => el.classList.remove('error'));

        let hasError = false;

        if (!name) {
            await showFieldError('prospect-name', 'Name is required');
            hasError = true;
        }

        if (!phone) {
            await showFieldError('prospect-phone', 'Phone is required');
            hasError = true;
        } else if (!/^[0-9\+\-\s]{8,}$/.test(phone)) {
            await showFieldError('prospect-phone', 'Enter a valid phone number (min 8 digits)');
            hasError = true;
        }

        if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
            await showFieldError('prospect-email', 'Invalid email format');
            hasError = true;
        }

        if (hasError) {
            UI.toast.error('Please fill in the required fields');
            document.querySelector('.form-control.error')?.scrollIntoView({ behavior: 'smooth', block: 'center' });
            return;
        }

        // Duplicate detection: block same name + IC or same name + phone
        if (!editId) {
            const ic = document.getElementById('prospect-ic')?.value?.trim();
            const normalize = str => str ? str.toLowerCase().replace(/\s+/g, '') : '';
            const normName = normalize(name);

            const existingProspects = await AppDataStore.getAll('prospects');
            const existingCustomers = await AppDataStore.getAll('customers');
            const allPeople = [...existingProspects, ...existingCustomers];

            const duplicate = allPeople.find(p => {
                const sameName = normalize(p.full_name) === normName;
                if (!sameName) return false;
                if (ic && p.ic_number && normalize(p.ic_number) === normalize(ic)) return true;
                if (phone && p.phone && normalize(p.phone) === normalize(phone)) return true;
                return false;
            });

            if (duplicate) {
                const type = existingProspects.find(p => p.id === duplicate.id) ? 'Prospect' : 'Customer';
                UI.toast.error(`Duplicate detected: "${duplicate.full_name}" already exists as a ${type} with the same name and ${duplicate.ic_number && normalize(duplicate.ic_number) === normalize(ic) ? 'IC number' : 'phone number'}.`);
                return;
            }
        }

        // Validate compulsory referral fields
        if (!_selectedProspectReferrer) {
            UI.toast.error('Referred By is required. Please search and select a referrer.');
            return;
        }
        const relationship = document.getElementById('prospect-relationship')?.value;
        if (!relationship) {
            UI.toast.error('Relationship is required.');
            return;
        }
        // All Basic Info fields pulled via the shared collector — keeps
        // CPS + Prospect forms in lockstep. Prospect-specific metadata
        // (responsible_agent_id, referred_by_*, pipeline_stage, score) below.
        const basic = collectBasicInfoData('prospect');
        const data = {
            ...basic,
            full_name: name, // validated above
            phone: phone,    // validated above
            referred_by: _selectedProspectReferrer?.name || null,
            referred_by_id: _selectedProspectReferrer?.id || null,
            referred_by_type: _selectedProspectReferrer?.type || null,
            responsible_agent_id: _currentUser?.id || null,
            cps_assignment_date: new Date().toISOString().split('T')[0],
            pipeline_stage: 'new',
            score: editId ? undefined : 200,
            expected_close_date: null,
            deal_value: 0,
        };

        // Capture snapshot before update for approval queue
        let snapshotBefore = null;
        if (editId) {
            snapshotBefore = await AppDataStore.getById('prospects', parseInt(editId));
        }

        try {
            if (editId) {
                await AppDataStore.update('prospects', parseInt(editId), data);
                UI.toast.success('Prospect updated successfully');

                // Create approval entry for non-manager edits — but ONLY when the
                // prospect has been converted to a customer. Pure prospects can be
                // edited freely; the approval queue exists to protect customer data,
                // not to gate every agent's edit on a prospect that isn't even a
                // customer yet. (Without this guard the super admin's queue gets
                // flooded with meaningless "Info Update" entries.)
                const isManager = isSystemAdmin(_currentUser) || isMarketingManager(_currentUser);
                const isConverted = snapshotBefore?.status === 'converted';
                if (!isManager && isConverted) {
                    try {
                        await AppDataStore.create('approval_queue', {
                            id: Date.now(),
                            approval_type: 'info_update',
                            status: 'pending',
                            prospect_id: parseInt(editId),
                            customer_id: null,
                            submitted_by: _currentUser?.id,
                            submitted_at: new Date().toISOString(),
                            snapshot_before: snapshotBefore,
                            snapshot_after: data,
                            description: `Information update for ${name}`
                        });
                    } catch (e) { /* approval queue write failed silently */ }
                }
            } else {
                data.id = Date.now();
                data.protection_deadline = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
                data.score = SCORING_RULES.CREATE_PROSPECT;
                data.created_at = new Date().toISOString();
                await AppDataStore.create('prospects', data);
                UI.toast.success('Prospect created successfully');
                document.dispatchEvent(new CustomEvent('prospectCreated', { detail: data }));
                // Trigger new_prospect workflow
                try { await executeWorkflows('new_prospect', { name: data.full_name }); } catch (e) { /* ignore */ }
            }
        } catch (err) {
            UI.toast.error('Save failed: ' + (err.message || 'Unknown error'));
            return;
        }

        UI.hideModal();
        await renderProspectsTable();
        if (editId) await showProspectDetail(parseInt(editId));
    };


    const filterProspects = async () => {
        _prospectPage = 0; // reset to first page when filters change
        await renderProspectsTable();
    };

