            postal_code: prospect.postal_code,
            lifetime_value: amount,
            status: 'active',
            customer_since: date || new Date().toISOString().split('T')[0],
            responsible_agent_id: prospect.responsible_agent_id || 5,
            converted_from_prospect_id: prospectId,
